{
  "name": "Lumina AI Workspace",
  "description": "A modern, all-in-one workspace for interacting with Google Gemini models. Features real-time chat, text generation, and visual analysis capabilities."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum AppMode {
  CHAT = 'CHAT',
  TEXT = 'TEXT',
  VISION = 'VISION'
}

export interface Message {
  id: string;
  role: 'user' | 'model';
  content: string;
  timestamp: number;
  isLoading?: boolean;
  image?: string; // base64 string for user uploaded images
}

export interface ChatState {
  messages: Message[];
  isTyping: boolean;
}

export interface GenerationConfig {
  temperature: number;
  topK: number;
  topP: number;
}

import { GoogleGenAI, GenerateContentResponse, Chat } from "@google/genai";
import { Message } from "../types";

// Initialize the client
// CRITICAL: process.env.API_KEY is automatically injected.
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const MODEL_NAME = "gemini-3-flash-preview";

export const generateTextStream = async (
  prompt: string, 
  onChunk: (text: string) => void
): Promise<string> => {
  try {
    const responseStream = await ai.models.generateContentStream({
      model: MODEL_NAME,
      contents: prompt,
    });

    let fullText = "";
    for await (const chunk of responseStream) {
        const text = chunk.text;
        if (text) {
            fullText += text;
            onChunk(text);
        }
    }
    return fullText;
  } catch (error) {
    console.error("Error generating text:", error);
    throw error;
  }
};

export const createChatSession = (): Chat => {
  return ai.chats.create({
    model: MODEL_NAME,
    config: {
        systemInstruction: "You are Lumina, a helpful, intelligent, and creative AI assistant. You provide clear, concise, and accurate answers using Markdown formatting."
    }
  });
};

export const sendMessageStream = async (
    chat: Chat, 
    message: string,
    onChunk: (text: string) => void
): Promise<string> => {
    try {
        const responseStream = await chat.sendMessageStream({
            message: message
        });

        let fullText = "";
        for await (const chunk of responseStream) {
            const text = chunk.text;
            if (text) {
                fullText += text;
                onChunk(text);
            }
        }
        return fullText;
    } catch (error) {
        console.error("Error sending chat message:", error);
        throw error;
    }
}

export const analyzeImage = async (
  base64Image: string,
  mimeType: string,
  prompt: string
): Promise<string> => {
  try {
    const response: GenerateContentResponse = await ai.models.generateContent({
      model: MODEL_NAME,
      contents: {
        parts: [
          {
            inlineData: {
              mimeType: mimeType,
              data: base64Image,
            },
          },
          {
            text: prompt || "Describe this image in detail.",
          },
        ],
      },
    });

    return response.text || "No analysis generated.";
  } catch (error) {
    console.error("Error analyzing image:", error);
    throw error;
  }
};

import React from 'react';
import ReactMarkdown from 'react-markdown';

interface MarkdownRendererProps {
  content: string;
}

export const MarkdownRenderer: React.FC<MarkdownRendererProps> = ({ content }) => {
  return (
    <div className="prose prose-invert prose-sm max-w-none break-words">
      <ReactMarkdown
        components={{
          code({ className, children, ...props }) {
            const match = /language-(\w+)/.exec(className || '')
            const isInline = !match && !String(children).includes('\n');

            return !isInline ? (
              <div className="rounded-md bg-slate-900 p-4 my-2 overflow-x-auto border border-slate-700">
                <code className={className} {...props}>
                  {children}
                </code>
              </div>
            ) : (
              <code className="bg-slate-800 rounded px-1 py-0.5 text-orange-300" {...props}>
                {children}
              </code>
            )
          }
        }}
      >
        {content}
      </ReactMarkdown>
    </div>
  );
};

import React from 'react';

export const Spinner: React.FC = () => (
  <div className="flex justify-center items-center space-x-2">
    <div className="w-2 h-2 bg-blue-400 rounded-full animate-bounce [animation-delay:-0.3s]"></div>
    <div className="w-2 h-2 bg-purple-400 rounded-full animate-bounce [animation-delay:-0.15s]"></div>
    <div className="w-2 h-2 bg-pink-400 rounded-full animate-bounce"></div>
  </div>
);

import React, { useState, useRef, useEffect } from 'react';
import { Send, User, Bot, Trash2 } from 'lucide-react';
import { Message } from '../types';
import { createChatSession, sendMessageStream } from '../services/geminiService';
import { MarkdownRenderer } from './MarkdownRenderer';
import { Spinner } from './Spinner';
import { Chat } from '@google/genai';

export const ChatInterface: React.FC = () => {
  const [messages, setMessages] = useState<Message[]>([
    {
      id: 'welcome',
      role: 'model',
      content: "Hello! I'm Lumina. How can I help you today?",
      timestamp: Date.now(),
    }
  ]);
  const [inputValue, setInputValue] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const chatSessionRef = useRef<Chat | null>(null);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    // Initialize chat session on mount
    chatSessionRef.current = createChatSession();
  }, []);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages, isTyping]);

  const handleSendMessage = async () => {
    if (!inputValue.trim() || !chatSessionRef.current) return;

    const userMessage: Message = {
      id: Date.now().toString(),
      role: 'user',
      content: inputValue,
      timestamp: Date.now(),
    };

    setMessages(prev => [...prev, userMessage]);
    setInputValue('');
    setIsTyping(true);

    const modelMessageId = (Date.now() + 1).toString();
    setMessages(prev => [
      ...prev,
      { id: modelMessageId, role: 'model', content: '', timestamp: Date.now(), isLoading: true }
    ]);

    try {
      let accumulatedText = "";

      await sendMessageStream(chatSessionRef.current, userMessage.content, (chunk) => {
        accumulatedText += chunk;
        setMessages(prev => prev.map(msg => 
          msg.id === modelMessageId 
            ? { ...msg, content: accumulatedText, isLoading: false } 
            : msg
        ));
      });

    } catch (error) {
      setMessages(prev => [
        ...prev,
        { id: Date.now().toString(), role: 'model', content: "Sorry, I encountered an error. Please try again.", timestamp: Date.now() }
      ]);
    } finally {
      setIsTyping(false);
    }
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSendMessage();
    }
  };

  const clearChat = () => {
    setMessages([{
      id: Date.now().toString(),
      role: 'model',
      content: "Chat cleared. Start a new conversation!",
      timestamp: Date.now(),
    }]);
    chatSessionRef.current = createChatSession();
  };

  return (
    <div className="flex flex-col h-full bg-slate-900/50 rounded-2xl border border-slate-700 overflow-hidden shadow-2xl backdrop-blur-sm">
      {/* Header */}
      <div className="p-4 border-b border-slate-700 bg-slate-900/80 flex justify-between items-center">
        <div className="flex items-center space-x-2">
            <div className="p-2 bg-indigo-600 rounded-lg">
                <Bot size={20} className="text-white" />
            </div>
            <h2 className="text-lg font-semibold text-white">Lumina Chat</h2>
        </div>
        <button 
            onClick={clearChat}
            className="p-2 text-slate-400 hover:text-red-400 hover:bg-slate-800 rounded-lg transition-colors"
            title="Clear Chat"
        >
            <Trash2 size={18} />
        </button>
      </div>

      {/* Messages Area */}
      <div className="flex-1 overflow-y-auto p-4 space-y-6">
        {messages.map((msg) => (
          <div
            key={msg.id}
            className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}
          >
            <div
              className={`max-w-[85%] rounded-2xl p-4 shadow-sm ${
                msg.role === 'user'
                  ? 'bg-indigo-600 text-white rounded-br-none'
                  : 'bg-slate-800 text-slate-200 border border-slate-700 rounded-bl-none'
              }`}
            >
              <div className="flex items-center space-x-2 mb-1 opacity-70 text-xs">
                {msg.role === 'user' ? <User size={12} /> : <Bot size={12} />}
                <span>{msg.role === 'user' ? 'You' : 'Lumina'}</span>
              </div>
              {msg.isLoading && !msg.content ? (
                 <Spinner />
              ) : (
                <MarkdownRenderer content={msg.content} />
              )}
            </div>
          </div>
        ))}
        {isTyping && messages[messages.length - 1]?.role === 'user' && (
             <div className="flex justify-start">
                 <div className="bg-slate-800 p-4 rounded-2xl rounded-bl-none border border-slate-700">
                     <Spinner />
                 </div>
             </div>
        )}
        <div ref={messagesEndRef} />
      </div>

      {/* Input Area */}
      <div className="p-4 bg-slate-900/80 border-t border-slate-700">
        <div className="relative flex items-center">
          <textarea
            value={inputValue}
            onChange={(e) => setInputValue(e.target.value)}
            onKeyDown={handleKeyDown}
            placeholder="Type your message..."
            className="w-full bg-slate-800 text-white placeholder-slate-400 rounded-xl py-3 pl-4 pr-12 resize-none h-[52px] focus:h-24 transition-[height] duration-200 focus:outline-none focus:ring-2 focus:ring-indigo-500 border border-slate-700"
          />
          <button
            onClick={handleSendMessage}
            disabled={!inputValue.trim() || isTyping}
            className="absolute right-2 top-2 p-2 bg-indigo-500 text-white rounded-lg hover:bg-indigo-600 disabled:opacity-50 disabled:cursor-not-allowed transition-colors"
          >
            <Send size={18} />
          </button>
        </div>
        <p className="text-center text-xs text-slate-500 mt-2">
          Lumina may display inaccurate info, including about people, so double-check its responses.
        </p>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { Sparkles, Copy, Check } from 'lucide-react';
import { generateTextStream } from '../services/geminiService';
import { MarkdownRenderer } from './MarkdownRenderer';
import { Spinner } from './Spinner';

export const TextInterface: React.FC = () => {
  const [prompt, setPrompt] = useState('');
  const [result, setResult] = useState('');
  const [isGenerating, setIsGenerating] = useState(false);
  const [copied, setCopied] = useState(false);

  const handleGenerate = async () => {
    if (!prompt.trim()) return;

    setIsGenerating(true);
    setResult('');
    setCopied(false);

    try {
      await generateTextStream(prompt, (chunk) => {
        setResult(prev => prev + chunk);
      });
    } catch (error) {
      setResult("Error generating text. Please check your network or API key.");
    } finally {
      setIsGenerating(false);
    }
  };

  const copyToClipboard = () => {
    navigator.clipboard.writeText(result);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  return (
    <div className="h-full flex flex-col md:flex-row gap-6">
      {/* Input Side */}
      <div className="flex-1 flex flex-col bg-slate-900/50 rounded-2xl border border-slate-700 p-6 shadow-xl backdrop-blur-sm">
        <h2 className="text-xl font-bold text-white mb-4 flex items-center">
            <Sparkles className="mr-2 text-yellow-400" size={24} />
            Creative Writer
        </h2>
        <div className="flex-1 flex flex-col">
            <label className="text-sm text-slate-400 mb-2">Enter your prompt</label>
            <textarea
            value={prompt}
            onChange={(e) => setPrompt(e.target.value)}
            placeholder="Write a blog post about the future of AI..."
            className="flex-1 w-full bg-slate-800 text-white placeholder-slate-500 rounded-xl p-4 resize-none focus:outline-none focus:ring-2 focus:ring-indigo-500 border border-slate-700 mb-4"
            />
            <button
            onClick={handleGenerate}
            disabled={!prompt.trim() || isGenerating}
            className="w-full py-3 bg-gradient-to-r from-indigo-500 to-purple-600 text-white font-semibold rounded-xl hover:opacity-90 transition-all disabled:opacity-50 disabled:cursor-not-allowed flex justify-center items-center shadow-lg"
            >
            {isGenerating ? <Spinner /> : 'Generate Content'}
            </button>
        </div>
      </div>

      {/* Output Side */}
      <div className="flex-1 flex flex-col bg-slate-900/50 rounded-2xl border border-slate-700 p-6 shadow-xl backdrop-blur-sm min-h-[400px]">
        <div className="flex justify-between items-center mb-4">
            <h2 className="text-xl font-bold text-white">Result</h2>
            {result && (
            <button
                onClick={copyToClipboard}
                className="flex items-center text-sm text-slate-400 hover:text-white transition-colors"
            >
                {copied ? <Check size={16} className="mr-1 text-green-400" /> : <Copy size={16} className="mr-1" />}
                {copied ? 'Copied' : 'Copy'}
            </button>
            )}
        </div>

        <div className="flex-1 overflow-y-auto bg-slate-800/50 rounded-xl p-4 border border-slate-700/50">
            {isGenerating && !result ? (
                <div className="h-full flex flex-col justify-center items-center text-slate-500">
                    <Spinner />
                    <p className="mt-4 text-sm animate-pulse">Crafting your content...</p>
                </div>
            ) : result ? (
                <MarkdownRenderer content={result} />
            ) : (
                <div className="h-full flex flex-col justify-center items-center text-slate-500 opacity-50">
                    <Sparkles size={48} className="mb-4" />
                    <p>Generated content will appear here</p>
                </div>
            )}
        </div>
      </div>
    </div>
  );
};

import React, { useState, useRef } from 'react';
import { Upload, Image as ImageIcon, Search, X } from 'lucide-react';
import { analyzeImage } from '../services/geminiService';
import { MarkdownRenderer } from './MarkdownRenderer';
import { Spinner } from './Spinner';

export const VisionInterface: React.FC = () => {
  const [selectedImage, setSelectedImage] = useState<string | null>(null);
  const [mimeType, setMimeType] = useState<string>('');
  const [prompt, setPrompt] = useState('');
  const [result, setResult] = useState('');
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFileChange = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (file) {
      if (file.size > 4 * 1024 * 1024) { // 4MB limit check
          alert("File size too large. Please select an image under 4MB.");
          return;
      }

      const reader = new FileReader();
      reader.onloadend = () => {
        const base64String = reader.result as string;
        // Extract base64 data and mime type
        const parts = base64String.split(',');
        const mime = parts[0].match(/:(.*?);/)?.[1] || 'image/png';
        const data = parts[1];

        setSelectedImage(base64String); // For display
        setMimeType(mime);
        setResult(''); // Clear previous results
      };
      reader.readAsDataURL(file);
    }
  };

  const handleAnalyze = async () => {
    if (!selectedImage || !mimeType) return;

    setIsAnalyzing(true);
    setResult('');

    try {
        // We need just the base64 data, not the prefix
        const base64Data = selectedImage.split(',')[1];
        const analysisText = await analyzeImage(base64Data, mimeType, prompt);
        setResult(analysisText);
    } catch (error) {
        setResult("Failed to analyze image. Please ensure the format is supported and try again.");
    } finally {
        setIsAnalyzing(false);
    }
  };

  const clearImage = () => {
      setSelectedImage(null);
      setMimeType('');
      setResult('');
      if (fileInputRef.current) fileInputRef.current.value = '';
  };

  return (
    <div className="h-full flex flex-col gap-6">
      <div className="bg-slate-900/50 rounded-2xl border border-slate-700 p-6 shadow-xl backdrop-blur-sm">
        <h2 className="text-xl font-bold text-white mb-6 flex items-center">
            <ImageIcon className="mr-2 text-pink-500" size={24} />
            Visual Analysis
        </h2>

        <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
            {/* Left Column: Input */}
            <div className="space-y-4">
                {/* Image Upload Area */}
                <div className={`relative border-2 border-dashed rounded-xl p-8 flex flex-col justify-center items-center text-center transition-all h-64 ${
                    selectedImage ? 'border-indigo-500 bg-slate-800/50' : 'border-slate-600 hover:border-slate-500 hover:bg-slate-800/30'
                }`}>
                    {selectedImage ? (
                        <div className="relative h-full w-full flex justify-center items-center">
                            <img src={selectedImage} alt="Preview" className="max-h-full max-w-full rounded-lg shadow-lg object-contain" />
                            <button 
                                onClick={clearImage}
                                className="absolute top-[-10px] right-[-10px] bg-red-500 text-white p-1 rounded-full hover:bg-red-600 shadow-md"
                            >
                                <X size={16} />
                            </button>
                        </div>
                    ) : (
                        <>
                            <Upload className="text-slate-400 mb-4" size={48} />
                            <p className="text-slate-300 font-medium">Click to upload an image</p>
                            <p className="text-slate-500 text-sm mt-2">JPEG, PNG, WEBP (Max 4MB)</p>
                            <input 
                                type="file" 
                                ref={fileInputRef}
                                onChange={handleFileChange}
                                accept="image/*"
                                className="absolute inset-0 w-full h-full opacity-0 cursor-pointer"
                            />
                        </>
                    )}
                </div>

                {/* Prompt Input */}
                <div className="relative">
                    <input
                        type="text"
                        value={prompt}
                        onChange={(e) => setPrompt(e.target.value)}
                        placeholder="Ask something about the image (optional)..."
                        className="w-full bg-slate-800 text-white placeholder-slate-500 rounded-xl py-3 pl-4 pr-12 focus:outline-none focus:ring-2 focus:ring-indigo-500 border border-slate-700"
                    />
                    <div className="absolute right-3 top-3 text-slate-400">
                        <Search size={20} />
                    </div>
                </div>

                <button
                    onClick={handleAnalyze}
                    disabled={!selectedImage || isAnalyzing}
                    className="w-full py-3 bg-gradient-to-r from-pink-500 to-rose-600 text-white font-semibold rounded-xl hover:opacity-90 transition-all disabled:opacity-50 disabled:cursor-not-allowed flex justify-center items-center shadow-lg"
                >
                    {isAnalyzing ? <Spinner /> : 'Analyze Image'}
                </button>
            </div>

            {/* Right Column: Output */}
            <div className="bg-slate-800/50 rounded-xl border border-slate-700/50 p-6 overflow-y-auto h-[400px] lg:h-auto">
                <h3 className="text-sm uppercase tracking-wider text-slate-400 font-semibold mb-4">Analysis Result</h3>

                {isAnalyzing ? (
                    <div className="h-full flex flex-col justify-center items-center text-slate-500">
                        <Spinner />
                        <p className="mt-4 text-sm animate-pulse">Vision model is analyzing...</p>
                    </div>
                ) : result ? (
                    <MarkdownRenderer content={result} />
                ) : (
                    <div className="h-full flex flex-col justify-center items-center text-slate-500 opacity-50">
                        <ImageIcon size={48} className="mb-4" />
                        <p>Upload an image to see insights here</p>
                    </div>
                )}
            </div>
        </div>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { MessageSquare, FileText, Image, Zap, Menu, X } from 'lucide-react';
import { AppMode } from './types';
import { ChatInterface } from './components/ChatInterface';
import { TextInterface } from './components/TextInterface';
import { VisionInterface } from './components/VisionInterface';

const App: React.FC = () => {
  const [activeMode, setActiveMode] = useState<AppMode>(AppMode.CHAT);
  const [mobileMenuOpen, setMobileMenuOpen] = useState(false);

  const toggleMobileMenu = () => setMobileMenuOpen(!mobileMenuOpen);

  const renderContent = () => {
    switch (activeMode) {
      case AppMode.CHAT:
        return <ChatInterface />;
      case AppMode.TEXT:
        return <TextInterface />;
      case AppMode.VISION:
        return <VisionInterface />;
      default:
        return <ChatInterface />;
    }
  };

  const navItems = [
    { mode: AppMode.CHAT, label: 'Chat', icon: MessageSquare, color: 'text-blue-400' },
    { mode: AppMode.TEXT, label: 'Text', icon: FileText, color: 'text-emerald-400' },
    { mode: AppMode.VISION, label: 'Vision', icon: Image, color: 'text-pink-400' },
  ];

  return (
    <div className="min-h-screen bg-background text-slate-200 font-sans selection:bg-indigo-500/30 selection:text-white overflow-hidden flex flex-col md:flex-row">

      {/* Sidebar Navigation (Desktop) */}
      <aside className="hidden md:flex flex-col w-64 bg-surface/50 border-r border-slate-800 p-4 backdrop-blur-md">
        <div className="flex items-center space-x-3 px-2 py-4 mb-8">
            <div className="p-2 bg-gradient-to-tr from-indigo-500 to-purple-600 rounded-lg shadow-lg shadow-indigo-500/20">
                <Zap size={24} className="text-white" />
            </div>
            <h1 className="text-xl font-bold bg-clip-text text-transparent bg-gradient-to-r from-white to-slate-400">
                Lumina
            </h1>
        </div>

        <nav className="flex-1 space-y-2">
            {navItems.map((item) => (
                <button
                    key={item.mode}
                    onClick={() => setActiveMode(item.mode)}
                    className={`w-full flex items-center space-x-3 px-4 py-3 rounded-xl transition-all duration-200 group ${
                        activeMode === item.mode 
                        ? 'bg-indigo-600/10 text-white border border-indigo-500/20 shadow-md' 
                        : 'text-slate-400 hover:bg-slate-800/50 hover:text-white'
                    }`}
                >
                    <item.icon size={20} className={`${activeMode === item.mode ? item.color : 'text-slate-500 group-hover:text-white'} transition-colors`} />
                    <span className="font-medium">{item.label}</span>
                </button>
            ))}
        </nav>

        <div className="mt-auto px-4 py-6 border-t border-slate-800/50">
            <p className="text-xs text-slate-500 text-center">
                Powered by Google Gemini
            </p>
        </div>
      </aside>

      {/* Mobile Header */}
      <div className="md:hidden flex items-center justify-between p-4 bg-surface border-b border-slate-800 sticky top-0 z-50">
         <div className="flex items-center space-x-2">
            <div className="p-1.5 bg-indigo-600 rounded-md">
                <Zap size={18} className="text-white" />
            </div>
            <span className="font-bold text-lg">Lumina</span>
         </div>
         <button onClick={toggleMobileMenu} className="p-2 text-slate-300">
             {mobileMenuOpen ? <X size={24} /> : <Menu size={24} />}
         </button>
      </div>

      {/* Mobile Menu Overlay */}
      {mobileMenuOpen && (
          <div className="md:hidden fixed inset-0 z-40 bg-slate-900/95 backdrop-blur-lg pt-20 px-6">
              <nav className="space-y-4">
                {navItems.map((item) => (
                    <button
                        key={item.mode}
                        onClick={() => {
                            setActiveMode(item.mode);
                            setMobileMenuOpen(false);
                        }}
                        className={`w-full flex items-center space-x-4 p-4 rounded-xl text-lg font-medium transition-all ${
                            activeMode === item.mode 
                            ? 'bg-indigo-600 text-white' 
                            : 'bg-slate-800 text-slate-400'
                        }`}
                    >
                        <item.icon size={24} />
                        <span>{item.label}</span>
                    </button>
                ))}
              </nav>
          </div>
      )}

