}

import { PastPaper, Subject, DifficultyLevel } from '../types';

export const SUBJECTS: Subject[] = [
  { id: 'phy-al', name: 'Physics', code: '9702', level: 'A Level' },
  { id: 'chem-al', name: 'Chemistry', code: '9701', level: 'A Level' },
  { id: 'math-al', name: 'Mathematics', code: '9709', level: 'A Level' },
  { id: 'cs-al', name: 'Computer Science', code: '9618', level: 'A Level' },
  { id: 'phy-ol', name: 'Physics', code: '5054', level: 'O Level' },
  { id: 'chem-ol', name: 'Chemistry', code: '5070', level: 'O Level' },
  { id: 'math-ol', name: 'Mathematics (D)', code: '4024', level: 'O Level' },
  { id: 'cs-ol', name: 'Computer Science', code: '2210', level: 'O Level' },
];

const calculateDifficulty = (threshold: number, total: number): DifficultyLevel => {
  const percentage = (threshold / total) * 100;

  // High threshold = Easier paper (Students found it easy to score high)
  // Low threshold = Harder paper (Students struggled)
  if (percentage >= 80) return 'Very Easy';
  if (percentage >= 73) return 'Easy';
  if (percentage >= 63) return 'Medium';
  if (percentage >= 53) return 'Hard';
  return 'Very Hard';
};

export const generateMockPapers = (subjectId: string): PastPaper[] => {
  const papers: PastPaper[] = [];
  const subject = SUBJECTS.find(s => s.id === subjectId);
  if (!subject) return [];

  const startYear = 2004;
  const endYear = 2024;

  const paperTypes = subject.level === 'A Level' ? [1, 2, 3, 4, 5] : [1, 2];

  for (let year = endYear; year >= startYear; year--) {
    ['May/June', 'Oct/Nov'].forEach(session => {
      paperTypes.forEach(pNum => {
         // Variants usually 1, 2, 3 depending on region, let's simulate 1 and 2
         [1, 2].forEach(vNum => {
            const variant = parseInt(`${pNum}${vNum}`); // e.g., Paper 1, Variant 2 = 12

            // Mock Data Generation Logic
            const totalMarks = pNum === 1 ? 40 : pNum === 2 ? 60 : pNum === 3 ? 40 : pNum === 4 ? 100 : 30;

            // Randomize threshold between 45% and 85% of total marks
            const randomFactor = 0.45 + (Math.random() * 0.4); 
            const threshold = Math.floor(totalMarks * randomFactor);

            papers.push({
                id: `${subject.code}-${year}-${session}-${variant}`,
                subjectId: subject.id,
                year,
                session: session as 'May/June' | 'Oct/Nov',
                paperNumber: pNum,
                variant: variant,
                totalMarks,
                aGradeThreshold: threshold,
                difficulty: calculateDifficulty(threshold, totalMarks),
                downloadUrl: '#'
            });
         });
      });
    });
  }
  return papers;
};

import { GoogleGenAI, Chat } from "@google/genai";

// Initialize the client
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const MODEL_NAME = "gemini-3-flash-preview";

export const createTutorSession = (subjectName: string): Chat => {
  return ai.chats.create({
    model: MODEL_NAME,
    config: {
        systemInstruction: `You are an expert Cambridge International Examinations (CAIE) tutor for ${subjectName || 'O and A Levels'}. 
        You help students solve past paper questions, explain difficult concepts, and provide marking scheme insights. 
        You are encouraging, precise, and use Markdown for mathematical formulas and structured answers. 
        If asked about specific past papers, assume the role of an examiner explaining the solution.`
    }
  });
};

export const sendMessageStream = async (
    chat: Chat, 
    message: string,
    onChunk: (text: string) => void
): Promise<string> => {
    try {
        const responseStream = await chat.sendMessageStream({
            message: message
        });

        let fullText = "";
        for await (const chunk of responseStream) {
            const text = chunk.text;
            if (text) {
                fullText += text;
                onChunk(text);
            }
        }
        return fullText;
    } catch (error) {
        console.error("Error sending chat message:", error);
        throw error;
    }
}

