import React, { useState, useRef, useEffect } from 'react';
import { Send, User, Bot, Trash2, GraduationCap } from 'lucide-react';
import { Message } from '../types';
import { createTutorSession, sendMessageStream } from '../services/geminiService';
import { MarkdownRenderer } from './MarkdownRenderer';
import { Spinner } from './Spinner';
import { Chat } from '@google/genai';

export const TutorInterface: React.FC = () => {
  const [messages, setMessages] = useState<Message[]>([
    {
      id: 'welcome',
      role: 'model',
      content: "Hello! I'm your CAIE AI Tutor. I can help you with Past Papers, Marking Schemes, and difficult concepts for O/A Levels. What subject are you studying today?",
      timestamp: Date.now(),
    }
  ]);
  const [inputValue, setInputValue] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const chatSessionRef = useRef<Chat | null>(null);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    // Initialize chat session on mount
    chatSessionRef.current = createTutorSession('O and A Levels');
  }, []);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages, isTyping]);

  const handleSendMessage = async () => {
    if (!inputValue.trim() || !chatSessionRef.current) return;

    const userMessage: Message = {
      id: Date.now().toString(),
      role: 'user',
      content: inputValue,
      timestamp: Date.now(),
    };

    setMessages(prev => [...prev, userMessage]);
    setInputValue('');
    setIsTyping(true);

    const modelMessageId = (Date.now() + 1).toString();
    setMessages(prev => [
      ...prev,
      { id: modelMessageId, role: 'model', content: '', timestamp: Date.now(), isLoading: true }
    ]);

    try {
      let accumulatedText = "";

      await sendMessageStream(chatSessionRef.current, userMessage.content, (chunk) => {
        accumulatedText += chunk;
        setMessages(prev => prev.map(msg => 
          msg.id === modelMessageId 
            ? { ...msg, content: accumulatedText, isLoading: false } 
            : msg
        ));
      });

    } catch (error) {
      setMessages(prev => [
        ...prev,
        { id: Date.now().toString(), role: 'model', content: "Sorry, I encountered an error connecting to the AI Tutor. Please check your internet or API key.", timestamp: Date.now() }
      ]);
    } finally {
      setIsTyping(false);
    }
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSendMessage();
    }
  };

  const clearChat = () => {
    setMessages([{
      id: Date.now().toString(),
      role: 'model',
      content: "Chat cleared. Ask me about any Paper, Question or Concept!",
      timestamp: Date.now(),
    }]);
    chatSessionRef.current = createTutorSession('O and A Levels');
  };

  return (
    <div className="flex flex-col h-full bg-slate-900/50 rounded-2xl border border-slate-700 overflow-hidden shadow-2xl backdrop-blur-sm">
      {/* Header */}
      <div className="p-4 border-b border-slate-700 bg-slate-900/80 flex justify-between items-center">
        <div className="flex items-center space-x-2">
            <div className="p-2 bg-emerald-600 rounded-lg">
                <GraduationCap size={20} className="text-white" />
            </div>
            <div>
                <h2 className="text-lg font-semibold text-white leading-tight">AI Tutor</h2>
                <p className="text-xs text-slate-400">Expert on Marking Schemes</p>
            </div>
        </div>
        <button 
            onClick={clearChat}
            className="p-2 text-slate-400 hover:text-red-400 hover:bg-slate-800 rounded-lg transition-colors"
            title="Clear Chat"
        >
            <Trash2 size={18} />
        </button>
      </div>

      {/* Messages Area */}
      <div className="flex-1 overflow-y-auto p-4 space-y-6">
        {messages.map((msg) => (
          <div
            key={msg.id}
            className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}
          >
            <div
              className={`max-w-[85%] rounded-2xl p-4 shadow-sm ${
                msg.role === 'user'
                  ? 'bg-emerald-600 text-white rounded-br-none'
                  : 'bg-slate-800 text-slate-200 border border-slate-700 rounded-bl-none'
              }`}
            >
              <div className="flex items-center space-x-2 mb-1 opacity-70 text-xs">
                {msg.role === 'user' ? <User size={12} /> : <Bot size={12} />}
                <span>{msg.role === 'user' ? 'Student' : 'Tutor'}</span>
              </div>
              {msg.isLoading && !msg.content ? (
                 <Spinner />
              ) : (
                <MarkdownRenderer content={msg.content} />
              )}
            </div>
          </div>
        ))}
        {isTyping && messages[messages.length - 1]?.role === 'user' && (
             <div className="flex justify-start">
                 <div className="bg-slate-800 p-4 rounded-2xl rounded-bl-none border border-slate-700">
                     <Spinner />
                 </div>
             </div>
        )}
        <div ref={messagesEndRef} />
      </div>

      {/* Input Area */}
      <div className="p-4 bg-slate-900/80 border-t border-slate-700">
        <div className="relative flex items-center">
          <textarea
            value={inputValue}
            onChange={(e) => setInputValue(e.target.value)}
            onKeyDown={handleKeyDown}
            placeholder="Ask about a specific year, variant or concept..."
            className="w-full bg-slate-800 text-white placeholder-slate-400 rounded-xl py-3 pl-4 pr-12 resize-none h-[52px] focus:h-24 transition-[height] duration-200 focus:outline-none focus:ring-2 focus:ring-emerald-500 border border-slate-700"
          />
          <button
            onClick={handleSendMessage}
            disabled={!inputValue.trim() || isTyping}
            className="absolute right-2 top-2 p-2 bg-emerald-500 text-white rounded-lg hover:bg-emerald-600 disabled:opacity-50 disabled:cursor-not-allowed transition-colors"
          >
            <Send size={18} />
          </button>
        </div>
      </div>
    </div>
  );
};

