const calculateDifficulty = (threshold: number, total: number): DifficultyLevel => {
  const percentage = (threshold / total) * 100;

  // High threshold = Easier paper (Students found it easy to score high)
  // Low threshold = Harder paper (Students struggled)
  if (percentage >= 80) return 'Very Easy';
  if (percentage >= 73) return 'Easy';
  if (percentage >= 63) return 'Medium';
  if (percentage >= 53) return 'Hard';
  return 'Very Hard';
};

export const generateMockPapers = (subjectId: string): PastPaper[] => {
  const papers: PastPaper[] = [];
  const subject = SUBJECTS.find(s => s.id === subjectId);
  if (!subject) return [];

  const startYear = 2004;
  const endYear = 2024;

  // Basic mock logic for papers: A Levels usually have 4-5 papers, O Levels 2 papers (sometimes 3 like Bio/Chem/Phy ATP)
  // For simplicity we will stick to generic 1-5 for A Level and 1-2 for O Level
  // except for Pak Studies/Islamiyat which strictly have 2.
  const paperTypes = subject.level === 'A Level' ? [1, 2, 3, 4, 5] : [1, 2];

  for (let year = endYear; year >= startYear; year--) {
    ['May/June', 'Oct/Nov'].forEach(session => {
      paperTypes.forEach(pNum => {
         // Variants usually 1, 2, 3 depending on region, let's simulate 1 and 2
         [1, 2].forEach(vNum => {
            const variant = parseInt(`${pNum}${vNum}`); // e.g., Paper 1, Variant 2 = 12

            // Mock Data Generation Logic
            let totalMarks = 60; // default
            if (pNum === 1) totalMarks = 40; // MCQs often 40
            else if (pNum === 4) totalMarks = 100; // P4 often 100
            else if (pNum === 5) totalMarks = 30; // P5 often 30
            else totalMarks = 60; // P2, P3 generic

            // Randomize threshold between 45% and 85% of total marks
            const randomFactor = 0.45 + (Math.random() * 0.4); 
            const threshold = Math.floor(totalMarks * randomFactor);

            papers.push({
                id: `${subject.code}-${year}-${session}-${variant}`,
                subjectId: subject.id,
                year,
                session: session as 'May/June' | 'Oct/Nov',
                paperNumber: pNum,
                variant: variant,
                totalMarks,
                aGradeThreshold: threshold,
                difficulty: calculateDifficulty(threshold, totalMarks),
                downloadUrl: '#'
            });
         });
      });
    });
  }
  return papers;
};

