                        <input 
                            type="text"
                            placeholder="Optional"
                            value={searchVariant}
                            onChange={(e) => setSearchVariant(e.target.value)}
                            className="w-full bg-white dark:bg-slate-800 text-slate-900 dark:text-white border border-blue-200 dark:border-blue-800 rounded-xl px-4 py-3 focus:ring-2 focus:ring-blue-500 outline-none shadow-sm placeholder-slate-400"
                        />
                     </div>
                </div>
            )}
        </div>
      </div>

      {/* Stats Summary (Conditional on View Mode) */}
      {viewMode === 'browse' && (
        <div className="grid grid-cols-2 md:grid-cols-4 gap-4 animate-in fade-in duration-500">
            <div className="bg-white/80 dark:bg-slate-800/50 p-4 rounded-xl border border-gray-200 dark:border-slate-700 shadow-sm">
                <span className="text-slate-500 dark:text-slate-400 text-xs">Total Papers</span>
                <p className="text-2xl font-bold text-slate-900 dark:text-white">{filteredPapers.length}</p>
            </div>
            <div className="bg-white/80 dark:bg-slate-800/50 p-4 rounded-xl border border-gray-200 dark:border-slate-700 shadow-sm">
                <span className="text-slate-500 dark:text-slate-400 text-xs">Subject Code</span>
                <p className="text-2xl font-bold text-slate-900 dark:text-white">{currentSubject?.code}</p>
            </div>
            <div className="bg-red-50 dark:bg-red-900/20 p-4 rounded-xl border border-red-200 dark:border-red-900/30">
                <span className="text-red-600 dark:text-red-400 text-xs">Very Hard Papers</span>
                <p className="text-2xl font-bold text-red-700 dark:text-red-200">{filteredPapers.filter(p => p.difficulty === 'Very Hard').length}</p>
            </div>
            <div className="bg-emerald-50 dark:bg-emerald-900/20 p-4 rounded-xl border border-emerald-200 dark:border-emerald-900/30">
                <span className="text-emerald-600 dark:text-emerald-400 text-xs">Easy Papers</span>
                <p className="text-2xl font-bold text-emerald-700 dark:text-emerald-200">{filteredPapers.filter(p => p.difficulty.includes('Easy')).length}</p>
            </div>
        </div>
      )}

      {/* Grid */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-4 overflow-y-auto pb-4 custom-scrollbar">
        {filteredPapers.map((paper) => (
            <PaperCard key={paper.id} paper={paper} subjectCode={currentSubject?.code || ''} />
        ))}
        {filteredPapers.length === 0 && (
            <div className="col-span-full flex flex-col items-center justify-center py-20 text-slate-500 dark:text-slate-500">
                <div className="bg-gray-100 dark:bg-slate-800/50 p-6 rounded-full mb-4">
                    <Search size={48} className="opacity-50" />
                </div>
                <h3 className="text-lg font-medium mb-2">No papers found</h3>
                <p className="text-sm opacity-70 text-center max-w-md">
                    {viewMode === 'search' 
                        ? `We couldn't find a paper for ${currentSubject?.name} in ${searchSession} ${searchYear} with variant ${searchVariant || 'any'}.`
                        : "Try adjusting your filters to see more results."}
                </p>
            </div>
        )}
      </div>
    </div>
  );
};

