import React, { useState, useMemo } from 'react';
import { PaperAttempt } from '../types';
import { Clock, Filter, ChevronDown, ChevronUp, History, Trophy, AlertCircle } from 'lucide-react';

interface HistoryViewProps {
  attempts: PaperAttempt[];
}

type SortOption = 'Year' | 'Correctness';

export const HistoryView: React.FC<HistoryViewProps> = ({ attempts }) => {
  const [sortOption, setSortOption] = useState<SortOption>('Year');
  const [expandedSubjects, setExpandedSubjects] = useState<Record<string, boolean>>({});

  const toggleSubject = (subjectName: string) => {
    setExpandedSubjects(prev => ({
        ...prev,
        [subjectName]: !prev[subjectName]
    }));
  };

  const getStatusColor = (attempt: PaperAttempt) => {
    if (attempt.userMarks > attempt.aGradeThreshold) {
        return 'bg-green-100 dark:bg-green-500/20 border-green-200 dark:border-green-500/50 text-green-800 dark:text-green-300';
    } else if (attempt.userMarks < attempt.aGradeThreshold) {
        return 'bg-red-100 dark:bg-red-500/20 border-red-200 dark:border-red-500/50 text-red-800 dark:text-red-300';
    } else {
        return 'bg-yellow-100 dark:bg-yellow-500/20 border-yellow-200 dark:border-yellow-500/50 text-yellow-800 dark:text-yellow-300';
    }
  };

  const getStatusLabel = (attempt: PaperAttempt) => {
    if (attempt.userMarks > attempt.aGradeThreshold) return 'Above Threshold (A)';
    if (attempt.userMarks < attempt.aGradeThreshold) return 'Below Threshold';
    return 'Met Threshold (A)';
  };

  const groupedAttempts = useMemo(() => {
    const grouped: Record<string, PaperAttempt[]> = {};

    // Group by Subject Name
    attempts.forEach(attempt => {
        const key = `${attempt.subjectName} (${attempt.subjectCode})`;
        if (!grouped[key]) {
            grouped[key] = [];
        }
        grouped[key].push(attempt);
    });

    // Sort within groups
    Object.keys(grouped).forEach(key => {
        grouped[key].sort((a, b) => {
            if (sortOption === 'Year') {
                // Descending year
                return b.year - a.year;
            } else {
                // Correctness: Green > Yellow > Red
                // We can assign scores: > is 3, = is 2, < is 1
                const getScore = (p: PaperAttempt) => {
                    if (p.userMarks > p.aGradeThreshold) return 3;
                    if (p.userMarks === p.aGradeThreshold) return 2;
                    return 1;
                };

                const scoreA = getScore(a);
                const scoreB = getScore(b);

                if (scoreA !== scoreB) {
                    return scoreB - scoreA; // Higher score first
                }

                // Tie breaker: higher marks percentage
                return (b.userMarks / b.totalMarks) - (a.userMarks / a.totalMarks);
            }
        });
    });

    // Make sure all subjects start expanded if it's the first render or assume expanded by default
    // Or we can just default expandedSubjects state to handle it.
    // Let's just return the grouped object.
    return grouped;
  }, [attempts, sortOption]);

  const subjectKeys = Object.keys(groupedAttempts).sort();

  return (
    <div className="h-full flex flex-col space-y-6">
      <div className="bg-white/70 dark:bg-slate-900/50 border border-gray-200 dark:border-slate-700 rounded-2xl p-6 backdrop-blur-sm shadow-xl dark:shadow-none">
        <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
            <div>
                <h2 className="text-2xl font-bold text-slate-900 dark:text-white flex items-center">
                    <History className="mr-3 text-orange-500" />
                    Attempt History
                </h2>
                <p className="text-slate-500 dark:text-slate-400 text-sm mt-1">
                    Track your performance across subjects
                </p>
            </div>

            <div className="flex items-center space-x-4">
                <span className="text-sm text-slate-500 dark:text-slate-400">Sort by:</span>
                <div className="flex bg-gray-100 dark:bg-slate-800 rounded-lg p-1 border border-gray-200 dark:border-slate-700">
                    <button 
                        onClick={() => setSortOption('Year')}
                        className={`px-4 py-2 rounded-md text-sm font-medium transition-all ${sortOption === 'Year' ? 'bg-white dark:bg-slate-600 text-slate-900 dark:text-white shadow-sm' : 'text-slate-500 dark:text-slate-400'}`}
                    >
                        Year
                    </button>
                    <button 
                        onClick={() => setSortOption('Correctness')}
                        className={`px-4 py-2 rounded-md text-sm font-medium transition-all ${sortOption === 'Correctness' ? 'bg-white dark:bg-slate-600 text-slate-900 dark:text-white shadow-sm' : 'text-slate-500 dark:text-slate-400'}`}
                    >
                        Performance
                    </button>
                </div>
            </div>
        </div>
      </div>

      <div className="flex-1 overflow-y-auto custom-scrollbar space-y-4 pb-10">
        {attempts.length === 0 ? (
            <div className="flex flex-col items-center justify-center h-64 text-slate-500 dark:text-slate-400">
                <Clock size={48} className="mb-4 opacity-50" />
                <p className="text-lg font-medium">No history yet</p>
                <p className="text-sm">Attempt papers in the Dashboard to see them here.</p>
            </div>
        ) : (
            subjectKeys.map(subject => (
                <div key={subject} className="bg-white dark:bg-slate-900/50 border border-gray-200 dark:border-slate-700 rounded-xl overflow-hidden shadow-sm">
                    <button 
                        onClick={() => toggleSubject(subject)}
                        className="w-full flex items-center justify-between p-4 bg-gray-50 dark:bg-slate-800/80 hover:bg-gray-100 dark:hover:bg-slate-800 transition-colors"
                    >
                        <div className="flex items-center space-x-3">
                            <span className="font-bold text-slate-800 dark:text-slate-200">{subject}</span>
                            <span className="px-2 py-0.5 rounded-full bg-slate-200 dark:bg-slate-700 text-xs font-mono text-slate-600 dark:text-slate-300">
                                {groupedAttempts[subject].length}
                            </span>
                        </div>
                        {expandedSubjects[subject] === false ? <ChevronDown size={20} /> : <ChevronUp size={20} />}
                    </button>

                    {(expandedSubjects[subject] !== false) && (
                        <div className="divide-y divide-gray-100 dark:divide-slate-800">
                            {groupedAttempts[subject].map(attempt => (
                                <div key={attempt.id} className={`p-4 flex flex-col md:flex-row md:items-center justify-between gap-4 border-l-4 ${attempt.userMarks > attempt.aGradeThreshold ? 'border-l-green-500' : attempt.userMarks < attempt.aGradeThreshold ? 'border-l-red-500' : 'border-l-yellow-500'}`}>
                                    <div className="flex-1">
                                        <div className="flex items-center gap-2 mb-1">
                                            <span className="font-bold text-slate-900 dark:text-white text-lg">
                                                {attempt.year} {attempt.session}
                                            </span>
                                            <span className="text-xs px-1.5 py-0.5 rounded bg-gray-100 dark:bg-slate-800 text-slate-500 dark:text-slate-400 border border-gray-200 dark:border-slate-700">
                                                Var {attempt.variant}
                                            </span>
                                            <span className="text-xs px-1.5 py-0.5 rounded bg-gray-100 dark:bg-slate-800 text-slate-500 dark:text-slate-400 border border-gray-200 dark:border-slate-700">
                                                Paper {attempt.paperNumber}
                                            </span>
                                        </div>
                                        <div className="flex items-center text-xs text-slate-500 dark:text-slate-400 gap-4">
                                            <span>Recorded: {new Date(attempt.timestamp).toLocaleDateString()}</span>
                                            <span className={`px-2 py-0.5 rounded-md font-medium border ${getStatusColor(attempt)}`}>
                                                {getStatusLabel(attempt)}
                                            </span>
                                        </div>
                                    </div>

                                    <div className="flex items-center gap-6">
                                        <div className="text-center">
                                            <span className="block text-xs text-slate-500 dark:text-slate-400 uppercase tracking-wider">A Grade</span>
                                            <span className="font-mono font-bold text-slate-700 dark:text-slate-300">
                                                {attempt.aGradeThreshold}
                                            </span>
                                        </div>
                                        <div className="text-center pl-6 border-l border-gray-200 dark:border-slate-700">
                                            <span className="block text-xs text-slate-500 dark:text-slate-400 uppercase tracking-wider">Your Score</span>
                                            <div className="flex items-end gap-1">
                                                <span className="text-2xl font-bold text-slate-900 dark:text-white leading-none">
                                                    {attempt.userMarks}
                                                </span>
                                                <span className="text-sm text-slate-500 dark:text-slate-400 mb-0.5">
                                                    / {attempt.totalMarks}
                                                </span>
                                            </div>
                                        </div>
                                    </div>
                                </div>
                            ))}
                        </div>
                    )}
                </div>
            ))
        )}
      </div>
    </div>
  );
};

import React, { useState, useMemo } from 'react';
import { PaperAttempt } from '../types';
import { Clock, Filter, ChevronDown, ChevronUp, History, Trophy, AlertCircle, Percent } from 'lucide-react';

interface HistoryViewProps {
  attempts: PaperAttempt[];
}

type SortOption = 'Year' | 'Correctness';

export const HistoryView: React.FC<HistoryViewProps> = ({ attempts }) => {
  const [sortOption, setSortOption] = useState<SortOption>('Year');
  const [expandedSubjects, setExpandedSubjects] = useState<Record<string, boolean>>({});

  const toggleSubject = (subjectName: string) => {
    setExpandedSubjects(prev => ({
        ...prev,
        [subjectName]: !prev[subjectName]
    }));
  };

  const getGradeInfo = (attempt: PaperAttempt) => {
    const percent = (attempt.userMarks / attempt.totalMarks) * 100;
    const aPercent = (attempt.aGradeThreshold / attempt.totalMarks) * 100;

    // Heuristic Grading Logic based on 'A' Threshold
    // A: >= Threshold
    // B: >= Threshold - 10%
    // C: >= Threshold - 20%
    // D: >= Threshold - 30%
    // E: >= Threshold - 40%

    let grade = 'U';
    if (attempt.userMarks >= attempt.aGradeThreshold) grade = 'A';
    else if (percent >= aPercent - 10) grade = 'B';
    else if (percent >= aPercent - 20) grade = 'C';
    else if (percent >= aPercent - 30) grade = 'D';
    else if (percent >= aPercent - 40) grade = 'E';

    let colorClass = '';
    // Green for A
    if (grade === 'A') {
        colorClass = 'bg-green-100 dark:bg-green-500/20 border-green-200 dark:border-green-500/50 text-green-800 dark:text-green-300';
    } 
    // Yellow for B or C
    else if (grade === 'B' || grade === 'C') {
        colorClass = 'bg-yellow-100 dark:bg-yellow-500/20 border-yellow-200 dark:border-yellow-500/50 text-yellow-800 dark:text-yellow-300';
    } 
    // Red for anything below (D, E, U)
    else {
        colorClass = 'bg-red-100 dark:bg-red-500/20 border-red-200 dark:border-red-500/50 text-red-800 dark:text-red-300';
    }

    return { grade, colorClass, percent: Math.round(percent) };
  };

  const groupedAttempts = useMemo(() => {
    const grouped: Record<string, PaperAttempt[]> = {};

    // Group by Subject Name
    attempts.forEach(attempt => {
        const key = `${attempt.subjectName} (${attempt.subjectCode})`;
        if (!grouped[key]) {
            grouped[key] = [];
        }
        grouped[key].push(attempt);
    });

    // Sort within groups
    Object.keys(grouped).forEach(key => {
        grouped[key].sort((a, b) => {
            if (sortOption === 'Year') {
                // Descending year
                return b.year - a.year;
            } else {
                // Correctness: Green (A) > Yellow (B/C) > Red (Others)
                const gradeA = getGradeInfo(a).grade;
                const gradeB = getGradeInfo(b).grade;

                const getScore = (g: string) => {
                    if (g === 'A') return 3;
                    if (g === 'B' || g === 'C') return 2;
                    return 1;
                };

                const scoreA = getScore(gradeA);
                const scoreB = getScore(gradeB);

                if (scoreA !== scoreB) {
                    return scoreB - scoreA; // Higher score first
                }

                // Tie breaker: higher percentage
                return (b.userMarks / b.totalMarks) - (a.userMarks / a.totalMarks);
            }
        });
    });

    return grouped;
  }, [attempts, sortOption]);

  const subjectKeys = Object.keys(groupedAttempts).sort();

  return (
    <div className="h-full flex flex-col space-y-6">
      <div className="bg-white/70 dark:bg-slate-900/50 border border-gray-200 dark:border-slate-700 rounded-2xl p-6 backdrop-blur-sm shadow-xl dark:shadow-none">
        <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
            <div>
                <h2 className="text-2xl font-bold text-slate-900 dark:text-white flex items-center">
                    <History className="mr-3 text-orange-500" />
                    Attempt History
                </h2>
                <p className="text-slate-500 dark:text-slate-400 text-sm mt-1">
                    Track your grades and performance
                </p>
            </div>

            <div className="flex items-center space-x-4">
                <span className="text-sm text-slate-500 dark:text-slate-400">Sort by:</span>
                <div className="flex bg-gray-100 dark:bg-slate-800 rounded-lg p-1 border border-gray-200 dark:border-slate-700">
                    <button 
                        onClick={() => setSortOption('Year')}
                        className={`px-4 py-2 rounded-md text-sm font-medium transition-all ${sortOption === 'Year' ? 'bg-white dark:bg-slate-600 text-slate-900 dark:text-white shadow-sm' : 'text-slate-500 dark:text-slate-400'}`}
                    >
                        Year
                    </button>
                    <button 
                        onClick={() => setSortOption('Correctness')}
                        className={`px-4 py-2 rounded-md text-sm font-medium transition-all ${sortOption === 'Correctness' ? 'bg-white dark:bg-slate-600 text-slate-900 dark:text-white shadow-sm' : 'text-slate-500 dark:text-slate-400'}`}
                    >
                        Grade (High to Low)
                    </button>
                </div>
            </div>
        </div>
      </div>

      <div className="flex-1 overflow-y-auto custom-scrollbar space-y-4 pb-10">
        {attempts.length === 0 ? (
            <div className="flex flex-col items-center justify-center h-64 text-slate-500 dark:text-slate-400">
                <Clock size={48} className="mb-4 opacity-50" />
                <p className="text-lg font-medium">No history yet</p>
                <p className="text-sm">Attempt papers in the Dashboard to see them here.</p>
            </div>
        ) : (
            subjectKeys.map(subject => (
