const calculateDifficulty = (threshold: number, total: number): DifficultyLevel => {
  const percentage = (threshold / total) * 100;
  if (percentage >= 80) return 'Very Easy';
  if (percentage >= 73) return 'Easy';
  if (percentage >= 63) return 'Medium';
  if (percentage >= 53) return 'Hard';
  return 'Very Hard';
};

const generateCaieUrl = (
  level: 'O Level' | 'A Level',
  subjectSlug: string,
  subjectCode: string,
  year: number,
  session: 'May/June' | 'Oct/Nov',
  paperNumber: number,
  variant: number,
  type: 'qp' | 'ms'
): string => {
  const levelPath = level === 'A Level' ? 'cambridge-international-a-level' : 'cambridge-o-level';
  const subjectPath = `${subjectSlug}-${subjectCode}`;
  const sessionCode = session === 'May/June' ? 's' : 'w';
  const yearShort = year.toString().slice(-2);
  const filename = `${subjectCode}_${sessionCode}${yearShort}_${type}_${variant}.pdf`;
  return `https://bestexamhelp.com/exam/${levelPath}/${subjectPath}/${year}/${filename}`;
};

export const generateMockPapers = (subjectId: string): PastPaper[] => {
  const papers: PastPaper[] = [];
  const subject = SUBJECTS.find(s => s.id === subjectId);
  if (!subject) return [];

  const startYear = 2004;
  const endYear = 2024;

  // Define paper types based on level and subject
  let paperTypes: number[];

  if (subject.level === 'O Level') {
      paperTypes = [1, 2];
  } else {
      // Default A Level papers (1-5 for Sciences)
      paperTypes = [1, 2, 3, 4, 5];

      // Mathematics (9709) includes Paper 6
      if (subject.code === '9709') {
          paperTypes = [1, 2, 3, 4, 5, 6];
      }
      // Subjects with fewer papers (e.g. CS, Eco, Bus, Law, His, Soc, Psy)
      else if (['9618', '9708', '9609', '9990', '9699', '9084', '9489'].includes(subject.code)) {
          paperTypes = [1, 2, 3, 4];
      }
      // Accounting (9706) usually P1, P2, P3 (P4 removed in newer syllabus, but kept clean here)
      else if (subject.code === '9706') {
          paperTypes = [1, 2, 3];
      }
  }

  for (let year = endYear; year >= startYear; year--) {
    let effectiveCode = subject.code;
    let effectiveSlug = subject.slug;

    if (subject.code === '9618' && year <= 2020) effectiveCode = '9608';
    if (subject.code === '9489' && year <= 2020) effectiveCode = '9389'; 
    if (subject.code === '7707' && year <= 2019) { 
        effectiveCode = '7110';
        effectiveSlug = 'principles-of-accounts';
    }

    ['May/June', 'Oct/Nov'].forEach(session => {
      paperTypes.forEach(pNum => {
         [1, 2].forEach(vNum => {
            const variant = parseInt(`${pNum}${vNum}`);

            // --- TOTAL MARKS LOGIC ---
            let totalMarks = 60; // Default fallback

            // 1. Sciences (Phy 9702, Chem 9701, Bio 9700)
            if (['9702', '9701', '9700'].includes(effectiveCode)) {
                if (pNum === 1) totalMarks = 40;
                else if (pNum === 2) totalMarks = 60;
                else if (pNum === 3) totalMarks = 40;
                else if (pNum === 4) totalMarks = 100;
                else if (pNum === 5) totalMarks = 30;
            }
            // 2. Mathematics (9709)
            else if (effectiveCode === '9709') {
                 if (pNum === 1 || pNum === 3) totalMarks = 75;
                 else totalMarks = 50; // P2, P4, P5, P6 are 50
            }
            // 3. Computer Science (9618, 9608) - ALL 75
            else if (effectiveCode === '9618' || effectiveCode === '9608') {
                totalMarks = 75;
            }
            // 4. Economics (9708)
            else if (effectiveCode === '9708') {
                if (pNum === 1 || pNum === 3) totalMarks = 30; // MCQs
                else if (pNum === 2) totalMarks = 60; // AS Data/Essay
                else if (pNum === 4) totalMarks = 60; // A2 Data/Essay
            }
            // 5. Business (9609)
            else if (effectiveCode === '9609') {
                if (pNum === 1) totalMarks = 40;
                else if (pNum === 2) totalMarks = 60;
                else if (pNum === 3) totalMarks = 60; 
                else if (pNum === 4) totalMarks = 40;
            }
            // 6. Psychology (9990)
            else if (effectiveCode === '9990') {
                totalMarks = 60; 
            }
            // 7. Sociology (9699)
            else if (effectiveCode === '9699') {
                if (pNum === 4) totalMarks = 70;
                else totalMarks = 50;
            }
            // 8. Law (9084)
            else if (effectiveCode === '9084') {
                if (pNum === 2) totalMarks = 50;
                else totalMarks = 75;
            }
            // 9. History (9489)
            else if (effectiveCode === '9489' || effectiveCode === '9389') {
                 if (pNum === 1) totalMarks = 40;
                 else if (pNum === 2) totalMarks = 60;
                 else if (pNum === 3) totalMarks = 40;
                 else if (pNum === 4) totalMarks = 60;
            }
            // 10. Accounting (9706)
            else if (effectiveCode === '9706') {
                 if (pNum === 1) totalMarks = 30;
                 else if (pNum === 2) totalMarks = 90;
                 else if (pNum === 3) totalMarks = 75;
            }
            // --- O Levels ---
            // 11. O Level CS (2210)
            else if (effectiveCode === '2210') {
                totalMarks = 75;
            }
            // 12. O Level Sciences (5054, 5070, 5090)
            else if (['5054', '5070', '5090'].includes(effectiveCode)) {
                 if (pNum === 1) totalMarks = 40;
                 else totalMarks = 80; // Theory
            }
            // 13. O Level Math (4024)
            else if (effectiveCode === '4024') {
                 if (pNum === 1) totalMarks = 80;
                 else totalMarks = 100;
            }

            const randomFactor = 0.55 + (Math.random() * 0.25); // Threshold between 55% and 80%
            const threshold = Math.floor(totalMarks * randomFactor);

            papers.push({
                id: `${effectiveCode}-${year}-${session}-${variant}`,
                subjectId: subject.id,
                year,
                session: session as 'May/June' | 'Oct/Nov',
                paperNumber: pNum,
                variant: variant,
                totalMarks,
                aGradeThreshold: threshold,
                difficulty: calculateDifficulty(threshold, totalMarks),
                downloadUrl: generateCaieUrl(
                    subject.level, effectiveSlug, effectiveCode, year, session as 'May/June' | 'Oct/Nov', pNum, variant, 'qp'
                ),
                markSchemeUrl: generateCaieUrl(
                    subject.level, effectiveSlug, effectiveCode, year, session as 'May/June' | 'Oct/Nov', pNum, variant, 'ms'
                )
            });
         });
      });
    });
  }
  return papers;
};

import React, { useState, useRef, useEffect } from 'react';
import { Send, User, Bot, Trash2, GraduationCap } from 'lucide-react';
import { Message } from '../types';
import { createTutorSession, sendMessageStream } from '../services/geminiService';
import { MarkdownRenderer } from './MarkdownRenderer';
import { Spinner } from './Spinner';
import { Chat } from '@google/genai';
import { SUBJECTS } from '../services/mockData';

export const TutorInterface: React.FC = () => {
  const [selectedSubjectId, setSelectedSubjectId] = useState<string>('all');
  const [messages, setMessages] = useState<Message[]>([]);
  const [inputValue, setInputValue] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const chatSessionRef = useRef<Chat | null>(null);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  const startNewSession = (subjectId: string) => {
    const subject = SUBJECTS.find(s => s.id === subjectId);
    const subjectName = subject ? `${subject.name} (${subject.level})` : 'O and A Levels';

    chatSessionRef.current = createTutorSession(subjectName);

    setMessages([{
      id: Date.now().toString(),
      role: 'model',
      content: `Hello! I'm your CAIE AI Tutor${subjectId !== 'all' ? ` for ${subjectName}` : ''}. I can help you with Past Papers, Marking Schemes, and difficult concepts.`,
      timestamp: Date.now(),
    }]);
  };

  useEffect(() => {
    startNewSession('all');
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  const handleSubjectChange = (e: React.ChangeEvent<HTMLSelectElement>) => {
      const newId = e.target.value;
      setSelectedSubjectId(newId);
      startNewSession(newId);
  };

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages, isTyping]);

  const handleSendMessage = async () => {
    if (!inputValue.trim() || !chatSessionRef.current) return;

    const userMessage: Message = {
      id: Date.now().toString(),
      role: 'user',
      content: inputValue,
      timestamp: Date.now(),
    };

    setMessages(prev => [...prev, userMessage]);
    setInputValue('');
    setIsTyping(true);

    const modelMessageId = (Date.now() + 1).toString();
    setMessages(prev => [
      ...prev,
      { id: modelMessageId, role: 'model', content: '', timestamp: Date.now(), isLoading: true }
    ]);

    try {
      let accumulatedText = "";

      await sendMessageStream(chatSessionRef.current, userMessage.content, (chunk) => {
        accumulatedText += chunk;
        setMessages(prev => prev.map(msg => 
          msg.id === modelMessageId 
            ? { ...msg, content: accumulatedText, isLoading: false } 
            : msg
        ));
      });

    } catch (error) {
      setMessages(prev => [
        ...prev,
        { id: Date.now().toString(), role: 'model', content: "Sorry, I encountered an error connecting to the AI Tutor. Please check your internet or API key.", timestamp: Date.now() }
      ]);
    } finally {
      setIsTyping(false);
    }
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSendMessage();
    }
  };

  const clearChat = () => {
    startNewSession(selectedSubjectId);
  };

  return (
    <div className="flex flex-col h-full bg-white/80 dark:bg-slate-900/50 rounded-2xl border border-gray-200 dark:border-slate-700 overflow-hidden shadow-xl dark:shadow-2xl backdrop-blur-sm">
      {/* Header */}
      <div className="p-4 border-b border-gray-200 dark:border-slate-700 bg-white/90 dark:bg-slate-900/80 flex flex-col sm:flex-row sm:justify-between sm:items-center gap-4">
        <div className="flex items-center space-x-2">
            <div className="p-2 bg-emerald-600 rounded-lg">
                <GraduationCap size={20} className="text-white" />
            </div>
            <div>
                <h2 className="text-lg font-semibold text-slate-900 dark:text-white leading-tight">AI Tutor</h2>
                <p className="text-xs text-slate-500 dark:text-slate-400">Expert on Marking Schemes</p>
            </div>
        </div>

        <div className="flex items-center gap-2 w-full sm:w-auto">
             <select 
                value={selectedSubjectId}
                onChange={handleSubjectChange}
                className="flex-1 sm:flex-none max-w-[200px] bg-gray-50 dark:bg-slate-800 border border-gray-200 dark:border-slate-700 text-slate-900 dark:text-white text-sm rounded-lg p-2 focus:ring-2 focus:ring-emerald-500 outline-none"
             >
                <option value="all">General Tutor</option>
                {SUBJECTS.map(s => (
                    <option key={s.id} value={s.id}>{s.name} ({s.level})</option>
                ))}
             </select>

            <button 
                onClick={clearChat}
                className="p-2 text-slate-400 hover:text-red-500 hover:bg-red-50 dark:hover:bg-slate-800 rounded-lg transition-colors"
                title="Clear Chat"
            >
                <Trash2 size={18} />
            </button>
        </div>
      </div>

      {/* Messages Area */}
      <div className="flex-1 overflow-y-auto p-4 space-y-6 custom-scrollbar">
        {messages.map((msg) => (
          <div
            key={msg.id}
            className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}
          >
            <div
              className={`max-w-[85%] rounded-2xl p-4 shadow-sm ${
                msg.role === 'user'
                  ? 'bg-emerald-600 text-white rounded-br-none'
                  : 'bg-gray-100 dark:bg-slate-800 text-slate-800 dark:text-slate-200 border border-gray-200 dark:border-slate-700 rounded-bl-none'
              }`}
            >
              <div className="flex items-center space-x-2 mb-1 opacity-70 text-xs">
                {msg.role === 'user' ? <User size={12} /> : <Bot size={12} />}
                <span>{msg.role === 'user' ? 'Student' : 'Tutor'}</span>
              </div>
              {msg.isLoading && !msg.content ? (
                 <Spinner />
              ) : (
                <MarkdownRenderer content={msg.content} />
              )}
            </div>
          </div>
        ))}
        {isTyping && messages[messages.length - 1]?.role === 'user' && (
             <div className="flex justify-start">
                 <div className="bg-gray-100 dark:bg-slate-800 p-4 rounded-2xl rounded-bl-none border border-gray-200 dark:border-slate-700">
                     <Spinner />
                 </div>
             </div>
        )}
        <div ref={messagesEndRef} />
      </div>

      {/* Input Area */}
      <div className="p-4 bg-white dark:bg-slate-900/80 border-t border-gray-200 dark:border-slate-700">
        <div className="relative flex items-center">
          <textarea
            value={inputValue}
            onChange={(e) => setInputValue(e.target.value)}
            onKeyDown={handleKeyDown}
            placeholder="Ask about a specific year, variant or concept..."
            className="w-full bg-gray-50 dark:bg-slate-800 text-slate-900 dark:text-white placeholder-slate-500 dark:placeholder-slate-400 rounded-xl py-3 pl-4 pr-12 resize-none h-[52px] focus:h-24 transition-[height] duration-200 focus:outline-none focus:ring-2 focus:ring-emerald-500 border border-gray-300 dark:border-slate-700 shadow-inner"
          />
          <button
            onClick={handleSendMessage}
            disabled={!inputValue.trim() || isTyping}
            className="absolute right-2 top-2 p-2 bg-emerald-500 text-white rounded-lg hover:bg-emerald-600 disabled:opacity-50 disabled:cursor-not-allowed transition-colors shadow-md"
          >
            <Send size={18} />
          </button>
        </div>
      </div>
    </div>
  );
};

