import React, { useState, useEffect, useRef } from 'react';
import { PastPaper, PaperAttempt } from '../types';
import { getPaperDuration } from '../services/mockData';
import { Timer, FileText, CheckCircle, AlertTriangle, ArrowLeft, Download } from 'lucide-react';

interface ExamInterfaceProps {
    paper: PastPaper;
    subjectName: string;
    subjectCode: string;
    onExit: () => void;
    onComplete: (attempt: PaperAttempt) => void;
}

export const ExamInterface: React.FC<ExamInterfaceProps> = ({ paper, subjectName, subjectCode, onExit, onComplete }) => {
    const [timeLeft, setTimeLeft] = useState<number>(() => {
        // Initial time based on paper duration (converted to seconds)
        // Assume A Level or O Level based on subjectCode heuristic or pass it down. 
        // For simplicity, checking if code starts with 9 (A Level) or not.
        const level = subjectCode.startsWith('9') ? 'A Level' : 'O Level';
        return getPaperDuration(paper.paperNumber, level) * 60; 
    });
    const [isActive, setIsActive] = useState(true);
    const [isFinished, setIsFinished] = useState(false);
    const [userMarks, setUserMarks] = useState('');
    const [gradeResult, setGradeResult] = useState<{grade: string, percentage: number} | null>(null);

    useEffect(() => {
        let interval: number | undefined;
        if (isActive && timeLeft > 0) {
            interval = window.setInterval(() => {
                setTimeLeft((prev) => prev - 1);
            }, 1000);
        } else if (timeLeft === 0) {
            finishExam();
        }
        return () => clearInterval(interval);
    }, [isActive, timeLeft]);

    const formatTime = (seconds: number) => {
        const h = Math.floor(seconds / 3600);
        const m = Math.floor((seconds % 3600) / 60);
        const s = seconds % 60;
        return `${h.toString().padStart(2, '0')}:${m.toString().padStart(2, '0')}:${s.toString().padStart(2, '0')}`;
    };

    const finishExam = () => {
        setIsActive(false);
        setIsFinished(true);
    };

    const handleSubmitScore = () => {
        const marks = parseInt(userMarks);
        if (isNaN(marks) || marks < 0 || marks > paper.totalMarks) {
            alert(`Please enter valid marks between 0 and ${paper.totalMarks}`);
            return;
        }

        const percentage = (marks / paper.totalMarks) * 100;
        const attempt: PaperAttempt = {
            id: Date.now().toString(),
            paperId: paper.id,
            subjectName: subjectName,
            subjectCode: subjectCode,
            year: paper.year,
            session: paper.session,
            variant: paper.variant,
            paperNumber: paper.paperNumber,
            userMarks: marks,
            totalMarks: paper.totalMarks,
            aGradeThreshold: paper.aGradeThreshold,
            timestamp: Date.now(),
            isExam: true
        };

        // Calculate Grade (Quick Logic for Display)
        let grade = 'U';
        const aPercent = (paper.aGradeThreshold / paper.totalMarks) * 100;
        if (marks >= paper.aGradeThreshold) grade = 'A';
        else if (percentage >= aPercent - 10) grade = 'B';
        else if (percentage >= aPercent - 20) grade = 'C';
        else if (percentage >= aPercent - 30) grade = 'D';
        else if (percentage >= aPercent - 40) grade = 'E';

        setGradeResult({ grade, percentage });
        onComplete(attempt);
    };

    if (gradeResult) {
        return (
            <div className="flex flex-col items-center justify-center h-full animate-in zoom-in duration-300">
                <div className="bg-white dark:bg-slate-800 p-8 rounded-2xl shadow-xl border border-gray-200 dark:border-slate-700 max-w-md w-full text-center">
                    <div className="w-20 h-20 bg-emerald-100 dark:bg-emerald-900/30 rounded-full flex items-center justify-center mx-auto mb-6">
                        <CheckCircle size={40} className="text-emerald-600 dark:text-emerald-400" />
                    </div>
                    <h2 className="text-3xl font-bold text-slate-900 dark:text-white mb-2">Exam Completed</h2>
                    <p className="text-slate-500 dark:text-slate-400 mb-6">
                        {subjectCode} - {paper.year} {paper.session} Paper {paper.paperNumber}
                    </p>

                    <div className="grid grid-cols-2 gap-4 mb-8">
                        <div className="bg-gray-50 dark:bg-slate-700/50 p-4 rounded-xl">
                            <span className="block text-xs text-slate-500 uppercase">Score</span>
                            <span className="text-2xl font-bold text-slate-900 dark:text-white">{userMarks} / {paper.totalMarks}</span>
                        </div>
                        <div className="bg-gray-50 dark:bg-slate-700/50 p-4 rounded-xl">
                            <span className="block text-xs text-slate-500 uppercase">Grade</span>
                            <span className={`text-2xl font-bold ${gradeResult.grade === 'A' ? 'text-green-600' : 'text-slate-900 dark:text-white'}`}>{gradeResult.grade}</span>
                        </div>
                    </div>

                    <button 
                        onClick={onExit}
                        className="w-full bg-indigo-600 hover:bg-indigo-700 text-white py-3 rounded-xl font-medium transition-colors"
                    >
                        Return to Dashboard
                    </button>
                </div>
            </div>
        );
    }

    return (
        <div className="h-full flex flex-col space-y-6 max-w-5xl mx-auto">
            {/* Header / Timer */}
            <div className={`bg-white dark:bg-slate-800 border-b-4 ${isActive ? 'border-orange-500' : 'border-slate-300 dark:border-slate-600'} p-6 rounded-xl shadow-sm flex flex-col md:flex-row justify-between items-center gap-4 transition-colors`}>
                <div>
                    <div className="flex items-center gap-3">
                         <h2 className="text-xl font-bold text-slate-900 dark:text-white">
                             {subjectName} <span className="text-slate-400 font-normal">({subjectCode})</span>
                         </h2>
                         <span className="px-2 py-0.5 bg-gray-100 dark:bg-slate-700 rounded text-xs font-mono text-slate-600 dark:text-slate-300">
                             {paper.year} {paper.session} P{paper.paperNumber}
                         </span>
                    </div>
                    <p className="text-sm text-slate-500 mt-1">
                        {isActive ? 'Exam in progress. Good luck!' : 'Exam finished. Time to mark your work.'}
                    </p>
                </div>

                <div className={`flex items-center gap-3 px-6 py-3 rounded-lg font-mono text-3xl font-bold ${isActive ? 'bg-orange-50 dark:bg-orange-900/20 text-orange-600 dark:text-orange-400' : 'bg-gray-100 dark:bg-slate-700 text-slate-500'}`}>
                    <Timer size={32} className={isActive ? 'animate-pulse' : ''} />
                    {formatTime(timeLeft)}
                </div>
            </div>

