const App: React.FC = () => {
  const [activeMode, setActiveMode] = useState<AppMode>(AppMode.PAPERS);
  const [mobileMenuOpen, setMobileMenuOpen] = useState(false);

  // Theme State
  const [theme, setTheme] = useState<'dark' | 'light'>(() => {
    if (typeof window !== 'undefined') {
        const saved = localStorage.getItem('theme');
        if (saved) return saved as 'dark' | 'light';
        return window.matchMedia('(prefers-color-scheme: dark)').matches ? 'dark' : 'light';
    }
    return 'dark';
  });

  // History State
  const [attempts, setAttempts] = useState<PaperAttempt[]>(() => {
    if (typeof window !== 'undefined') {
        const saved = localStorage.getItem('paperAttempts');
        return saved ? JSON.parse(saved) : [];
    }
    return [];
  });

  // Apply Theme
  useEffect(() => {
    const root = window.document.documentElement;
    if (theme === 'dark') {
      root.classList.add('dark');
    } else {
      root.classList.remove('dark');
    }
    localStorage.setItem('theme', theme);
  }, [theme]);

  // Save attempts to local storage
  useEffect(() => {
    localStorage.setItem('paperAttempts', JSON.stringify(attempts));
  }, [attempts]);

  const toggleTheme = () => {
    setTheme(prev => prev === 'dark' ? 'light' : 'dark');
  };

  const toggleMobileMenu = () => setMobileMenuOpen(!mobileMenuOpen);

  const handleSaveAttempt = (attempt: PaperAttempt) => {
    setAttempts(prev => {
        // Remove existing attempt for this specific paper if exists, then add new one
        const filtered = prev.filter(p => p.paperId !== attempt.paperId);
        return [attempt, ...filtered];
    });
  };

  const renderContent = () => {
    switch (activeMode) {
      case AppMode.PAPERS:
        return <Dashboard onSaveAttempt={handleSaveAttempt} existingAttempts={attempts} />;
      case AppMode.EXAM:
        return <ExamDashboard onSaveAttempt={handleSaveAttempt} existingAttempts={attempts} />;
      case AppMode.TUTOR:
        return <TutorInterface />;
      case AppMode.HISTORY:
        return <HistoryView attempts={attempts} />;
      default:
        return <Dashboard onSaveAttempt={handleSaveAttempt} existingAttempts={attempts} />;
    }
  };

  const navItems = [
    { mode: AppMode.PAPERS, label: 'Past Papers', icon: FileText, color: 'text-blue-500 dark:text-blue-400' },
