                            <span className="flex items-center justify-center gap-1 text-xs text-slate-500 uppercase font-semibold mb-1">
                                <Award size={12} /> Grade
                            </span>
                            <span className={`text-3xl font-extrabold ${gradeResult.grade === 'A' ? 'text-emerald-600 dark:text-emerald-400' : 'text-slate-900 dark:text-white'}`}>
