                            </div>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
};

import React, { useState, useRef, useEffect } from 'react';
import { Send, User, Bot, Trash2, GraduationCap, Sparkles, ArrowRight, Lightbulb, MessageSquare } from 'lucide-react';
import { Message } from '../types';
import { createTutorSession, sendMessageStream } from '../services/geminiService';
import { MarkdownRenderer } from './MarkdownRenderer';
import { Spinner } from './Spinner';
import { Chat } from '@google/genai';
import { SUBJECTS } from '../services/mockData';

export const TutorInterface: React.FC = () => {
  const [selectedSubjectId, setSelectedSubjectId] = useState<string>('all');
  const [messages, setMessages] = useState<Message[]>([]);
  const [inputValue, setInputValue] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const chatSessionRef = useRef<Chat | null>(null);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  const startNewSession = (subjectId: string) => {
    const subject = SUBJECTS.find(s => s.id === subjectId);
    const subjectName = subject ? `${subject.name} (${subject.level})` : 'O and A Levels';

    chatSessionRef.current = createTutorSession(subjectName);

    setMessages([{
      id: Date.now().toString(),
      role: 'model',
      content: `Hello! I'm your CAIE AI Tutor${subjectId !== 'all' ? ` for ${subjectName}` : ''}. I can help you with Past Papers, Marking Schemes, and difficult concepts.`,
      timestamp: Date.now(),
    }]);
  };

  useEffect(() => {
    startNewSession('all');
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  const handleSubjectChange = (e: React.ChangeEvent<HTMLSelectElement>) => {
      const newId = e.target.value;
      setSelectedSubjectId(newId);
      startNewSession(newId);
  };

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages, isTyping]);

  const handleSendMessage = async (text: string = inputValue) => {
    if (!text.trim() || !chatSessionRef.current) return;

    const userMessage: Message = {
      id: Date.now().toString(),
      role: 'user',
      content: text,
      timestamp: Date.now(),
    };

    setMessages(prev => [...prev, userMessage]);
    setInputValue('');
    setIsTyping(true);

    const modelMessageId = (Date.now() + 1).toString();
    setMessages(prev => [
      ...prev,
      { id: modelMessageId, role: 'model', content: '', timestamp: Date.now(), isLoading: true }
    ]);

    try {
      let accumulatedText = "";

      await sendMessageStream(chatSessionRef.current, userMessage.content, (chunk) => {
        accumulatedText += chunk;
        setMessages(prev => prev.map(msg => 
          msg.id === modelMessageId 
            ? { ...msg, content: accumulatedText, isLoading: false } 
            : msg
        ));
      });

    } catch (error) {
      setMessages(prev => [
        ...prev,
        { id: Date.now().toString(), role: 'model', content: "Sorry, I encountered an error connecting to the AI Tutor. Please check your internet or API key.", timestamp: Date.now() }
      ]);
    } finally {
      setIsTyping(false);
    }
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSendMessage();
    }
  };

  const clearChat = () => {
    startNewSession(selectedSubjectId);
  };

  const getSuggestions = (subjectId: string) => {
    const subject = SUBJECTS.find(s => s.id === subjectId);

    if (!subject) return [
        { icon: Lightbulb, text: "How do I calculate grade thresholds?" },
        { icon: GraduationCap, text: "Tips for managing exam time?" },
        { icon: MessageSquare, text: "Explain the difference between A Level and AS Level." },
        { icon: Sparkles, text: "How do I prepare for O Levels?" }
    ];

    if (subject.slug === 'physics') return [
        { icon: Lightbulb, text: "Explain Projectile Motion with examples." },
        { icon: GraduationCap, text: "Tips for Physics practical exams (Paper 3)." },
        { icon: MessageSquare, text: "What is the difference between potential and kinetic energy?" },
        { icon: Sparkles, text: "Solve a tricky circuit problem." }
    ];

    if (subject.slug === 'chemistry') return [
        { icon: Lightbulb, text: "Explain Hybridization in organic chemistry." },
        { icon: GraduationCap, text: "How to balance redox equations?" },
        { icon: MessageSquare, text: "Trends in the Periodic Table." },
        { icon: Sparkles, text: "Explain the Haber Process." }
    ];

    if (subject.slug.includes('math')) return [
        { icon: Lightbulb, text: "Explain Integration by Parts." },
        { icon: GraduationCap, text: "How to solve differential equations?" },
        { icon: MessageSquare, text: "Explain Normal Distribution statistics." },
        { icon: Sparkles, text: "Trigonometric identities cheat sheet." }
    ];

     if (subject.slug === 'computer-science') return [
        { icon: Lightbulb, text: "Explain the Fetch-Decode-Execute cycle." },
        { icon: GraduationCap, text: "Difference between TCP and UDP?" },
        { icon: MessageSquare, text: "How to convert Binary to Hexadecimal?" },
        { icon: Sparkles, text: "Explain Object Oriented Programming concepts." }
    ];

    return [
        { icon: Lightbulb, text: `What are the hardest topics in ${subject.name}?` },
        { icon: GraduationCap, text: `Explain a complex concept in ${subject.name}.` },
        { icon: MessageSquare, text: `Give me a practice question for ${subject.code}.` },
        { icon: Sparkles, text: `How to score an A* in ${subject.name}?` }
    ];
  };

  return (
    <div className="flex flex-col h-full bg-white dark:bg-slate-900 rounded-2xl border border-gray-200 dark:border-slate-700 overflow-hidden shadow-xl dark:shadow-2xl relative">
      {/* Decorative Background */}
      <div className="absolute top-0 left-0 w-full h-full overflow-hidden pointer-events-none z-0">
          <div className="absolute top-[-10%] right-[-10%] w-[300px] h-[300px] bg-emerald-500/5 dark:bg-emerald-500/10 rounded-full blur-[80px]" />
          <div className="absolute bottom-[-10%] left-[-10%] w-[300px] h-[300px] bg-blue-500/5 dark:bg-blue-500/10 rounded-full blur-[80px]" />
      </div>

      {/* Header */}
      <div className="relative z-10 p-4 border-b border-gray-200 dark:border-slate-800 bg-white/80 dark:bg-slate-900/80 backdrop-blur-md flex flex-col sm:flex-row sm:justify-between sm:items-center gap-4">
        <div className="flex items-center space-x-3">
            <div className="p-2.5 bg-gradient-to-br from-emerald-500 to-teal-600 rounded-xl shadow-lg shadow-emerald-500/20">
                <Bot size={24} className="text-white" />
