                  ? 'bg-gradient-to-br from-emerald-600 to-teal-600 text-white rounded-br-none'
                  : 'bg-white dark:bg-slate-800 text-slate-800 dark:text-slate-200 border border-gray-200 dark:border-slate-700 rounded-bl-none shadow-md dark:shadow-none'
              }`}
            >
               {msg.role === 'model' && (
                   <div className="absolute -left-10 top-0 p-1.5 bg-white dark:bg-slate-800 rounded-full border border-gray-200 dark:border-slate-700 shadow-sm hidden md:block">
                       <Bot size={16} className="text-emerald-600 dark:text-emerald-400" />
                   </div>
               )}

              <div className="flex items-center space-x-2 mb-2 opacity-80 text-[10px] uppercase tracking-wider font-bold">
