                 <div className="py-2 px-1">
                    <Spinner />
                 </div>
              ) : (
                <MarkdownRenderer content={msg.content} />
              )}
            </div>
          </div>
        ))}

        {/* Suggestion Chips (Only show if just the greeting exists) */}
        {messages.length <= 1 && !isTyping && (
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4 mt-8 px-4 animate-in fade-in slide-in-from-bottom-4 delay-200">
                {getSuggestions(selectedSubjectId).map((suggestion, idx) => (
