  type: 'qp' | 'ms'
): string => {
  const levelPath = level === 'A Level' ? 'cambridge-international-a-level' : 'cambridge-o-level';
  const subjectPath = `${subjectSlug}-${subjectCode}`;
  const sessionCode = session === 'May/June' ? 's' : 'w';
  const yearShort = year.toString().slice(-2);
  const filename = `${subjectCode}_${sessionCode}${yearShort}_${type}_${variant}.pdf`;
  return `https://bestexamhelp.com/exam/${levelPath}/${subjectPath}/${year}/${filename}`;
};

// Helper to estimate duration in minutes
export const getPaperDuration = (paperNumber: number, level: 'O Level' | 'A Level'): number => {
    if (level === 'O Level') {
        if (paperNumber === 1) return 60; // MCQs usually 1h
        return 90; // Theory usually 1h 30m - 2h
    } else {
        // A Level
        if (paperNumber === 1) return 75; // 1h 15m
        if (paperNumber === 2) return 75; // AS Structured
        if (paperNumber === 3) return 120; // Advanced Practical
        if (paperNumber === 4) return 120; // A2 Structured
        if (paperNumber === 5) return 75; // Planning/Analysis
        if (paperNumber === 6) return 60; // Stats/Probability (Maths)
        return 90;
    }
};

// Deterministic pseudo-random number generator for historical fallbacks
const seededRandom = (seed: number) => {
    const x = Math.sin(seed) * 10000;
    return x - Math.floor(x);
};

export const generateMockPapers = (subjectId: string): PastPaper[] => {
  const papers: PastPaper[] = [];
  const subject = SUBJECTS.find(s => s.id === subjectId);
  if (!subject) return [];

  const startYear = 2010; // Capped at 2010 for reliable data coverage
  const endYear = 2024;

  // Define paper types based on level and subject
  let paperTypes: number[];

  if (subject.level === 'O Level') {
      paperTypes = [1, 2];
  } else {
      paperTypes = [1, 2, 3, 4, 5];
      if (subject.code === '9709') paperTypes = [1, 2, 3, 4, 5, 6];
      else if (['9618', '9708', '9609', '9990', '9699', '9084', '9489'].includes(subject.code)) paperTypes = [1, 2, 3, 4];
      else if (subject.code === '9706') paperTypes = [1, 2, 3];
  }

  for (let year = endYear; year >= startYear; year--) {
    let effectiveCode = subject.code;
    let effectiveSlug = subject.slug;

    if (subject.code === '9618' && year <= 2020) effectiveCode = '9608';
    if (subject.code === '9489' && year <= 2020) effectiveCode = '9389'; 
    if (subject.code === '7707' && year <= 2019) { 
        effectiveCode = '7110';
        effectiveSlug = 'principles-of-accounts';
    }

    ['May/June', 'Oct/Nov'].forEach(session => {
      paperTypes.forEach(pNum => {
         [1, 2, 3].forEach(vNum => { // Include Variant 3 (common in many zones)
            const variant = parseInt(`${pNum}${vNum}`);

            // --- TOTAL MARKS LOGIC ---
            let totalMarks = 60; // Default fallback

            // 1. Sciences (Phy 9702, Chem 9701, Bio 9700)
            if (['9702', '9701', '9700'].includes(effectiveCode)) {
                if (pNum === 1) totalMarks = 40;
                else if (pNum === 2) totalMarks = 60;
                else if (pNum === 3) totalMarks = 40;
                else if (pNum === 4) totalMarks = 100;
                else if (pNum === 5) totalMarks = 30;
            }
            // 2. Mathematics (9709)
            else if (effectiveCode === '9709') {
                 if (pNum === 1 || pNum === 3) totalMarks = 75;
                 else totalMarks = 50; 
            }
            // 3. Computer Science (9618, 9608)
            else if (effectiveCode === '9618' || effectiveCode === '9608') {
                totalMarks = 75;
            }
            // 4. Economics (9708)
            else if (effectiveCode === '9708') {
                if (pNum === 1 || pNum === 3) totalMarks = 30;
                else if (pNum === 2) totalMarks = 60;
                else if (pNum === 4) totalMarks = 60;
            }
            // 5. Business (9609)
            else if (effectiveCode === '9609') {
                if (pNum === 1) totalMarks = 40;
                else if (pNum === 2) totalMarks = 60;
                else if (pNum === 3) totalMarks = 60; 
                else if (pNum === 4) totalMarks = 40;
            }
            // 6. Psychology (9990)
            else if (effectiveCode === '9990') totalMarks = 60; 
            // 7. Sociology (9699)
            else if (effectiveCode === '9699') {
                if (pNum === 4) totalMarks = 70;
                else totalMarks = 50;
            }
            // 8. Law (9084)
            else if (effectiveCode === '9084') {
                if (pNum === 2) totalMarks = 50;
                else totalMarks = 75;
            }
            // 9. History (9489)
            else if (effectiveCode === '9489' || effectiveCode === '9389') {
                 if (pNum === 1) totalMarks = 40;
                 else if (pNum === 2) totalMarks = 60;
                 else if (pNum === 3) totalMarks = 40;
                 else if (pNum === 4) totalMarks = 60;
            }
            // 10. Accounting (9706)
            else if (effectiveCode === '9706') {
                 if (pNum === 1) totalMarks = 30;
                 else if (pNum === 2) totalMarks = 90;
                 else if (pNum === 3) totalMarks = 75;
            }
            // --- O Levels ---
            // 11. O Level CS (2210)
            else if (effectiveCode === '2210') totalMarks = 75;
            // 12. O Level Sciences (5054, 5070, 5090)
            else if (['5054', '5070', '5090'].includes(effectiveCode)) {
                 if (pNum === 1) totalMarks = 40;
                 else totalMarks = 80;
            }
            // 13. O Level Math (4024)
            else if (effectiveCode === '4024') {
                 if (pNum === 1) totalMarks = 80;
                 else totalMarks = 100;
            }

            // --- THRESHOLD LOGIC ---

            let threshold: number;

            // 1. Try to find Official Threshold (Matches specific key)
            const sessionKey = session === 'May/June' ? 's' : 'w';
            const lookupKey = `${effectiveCode}-${year}-${sessionKey}-${pNum}${vNum}`;
            const lookupKeyVariantLess = `${effectiveCode}-${year}-${sessionKey}-${pNum}2`; // Try Variant 2 as default if exact not found

            if (OFFICIAL_THRESHOLDS[lookupKey]) {
                threshold = OFFICIAL_THRESHOLDS[lookupKey];
            } else if (OFFICIAL_THRESHOLDS[lookupKeyVariantLess]) {
                // If specific variant is missing (e.g., old years only captured variant 2), use variant 2 proxy
                threshold = OFFICIAL_THRESHOLDS[lookupKeyVariantLess];
            } else {
                // 3. Accurate Interpolation for data gaps (Rare with this DB)
                // Use closest year available
                let referenceYear = year;
                while(referenceYear < 2024 && !OFFICIAL_THRESHOLDS[`${effectiveCode}-${referenceYear}-${sessionKey}-${pNum}2`]) {
                    referenceYear++;
                }

                const refKey = `${effectiveCode}-${referenceYear}-${sessionKey}-${pNum}2`;
                if (OFFICIAL_THRESHOLDS[refKey]) {
                    threshold = OFFICIAL_THRESHOLDS[refKey];
                } else {
                    // Fallback to average percentages if no close year found (Very old papers)
                     let basePercent = 0.65; 
                    if (pNum === 1) basePercent = 0.72; 
                    else if (pNum === 3 || pNum === 5) basePercent = 0.68;
                    else if (pNum === 2 || pNum === 4) basePercent = 0.60;
                    threshold = Math.floor(totalMarks * basePercent);
                }
            }

            papers.push({
                id: `${effectiveCode}-${year}-${session}-${variant}`,
                subjectId: subject.id,
                year,
                session: session as 'May/June' | 'Oct/Nov',
                paperNumber: pNum,
                variant: variant,
                totalMarks,
                aGradeThreshold: threshold,
                difficulty: calculateDifficulty(threshold, totalMarks),
                downloadUrl: generateCaieUrl(
                    subject.level, effectiveSlug, effectiveCode, year, session as 'May/June' | 'Oct/Nov', pNum, variant, 'qp'
                ),
                markSchemeUrl: generateCaieUrl(
                    subject.level, effectiveSlug, effectiveCode, year, session as 'May/June' | 'Oct/Nov', pNum, variant, 'ms'
                )
            });
         });
      });
    });
  }
  return papers;
};

import React, { useState, useEffect, useMemo } from 'react';
import { PastPaper, PaperAttempt } from '../types';
import { getPaperDuration, getSubjectsTopics } from '../services/mockData';
import { generateExamFeedback } from '../services/geminiService';
import { MarkdownRenderer } from './MarkdownRenderer';
import { Spinner } from './Spinner';
import { Timer, FileText, CheckCircle, AlertTriangle, ArrowLeft, Download, Award, BarChart, Clock, Sparkles, Tag, ChevronRight } from 'lucide-react';

interface ExamInterfaceProps {
    paper: PastPaper;
    subjectName: string;
    subjectCode: string;
    onExit: () => void;
    onComplete: (attempt: PaperAttempt) => void;
}

export const ExamInterface: React.FC<ExamInterfaceProps> = ({ paper, subjectName, subjectCode, onExit, onComplete }) => {
    const totalDuration = useMemo(() => {
        const level = subjectCode.startsWith('9') ? 'A Level' : 'O Level';
        return getPaperDuration(paper.paperNumber, level) * 60; 
    }, [paper.paperNumber, subjectCode]);

    const availableTopics = useMemo(() => getSubjectsTopics(subjectCode), [subjectCode]);

    const [timeLeft, setTimeLeft] = useState<number>(totalDuration);
    const [isActive, setIsActive] = useState(true);
    const [isFinished, setIsFinished] = useState(false);
    const [userMarks, setUserMarks] = useState('');
    const [gradeResult, setGradeResult] = useState<{grade: string, percentage: number} | null>(null);
    const [showExitConfirm, setShowExitConfirm] = useState(false);

    // Topic Tagging State
    const [selectedTopics, setSelectedTopics] = useState<string[]>([]);

    // AI Feedback State
    const [aiFeedback, setAiFeedback] = useState<string>('');
    const [isLoadingFeedback, setIsLoadingFeedback] = useState(false);

    useEffect(() => {
        let interval: number | undefined;
        if (isActive && timeLeft > 0) {
            interval = window.setInterval(() => {
                setTimeLeft((prev) => prev - 1);
            }, 1000);
        } else if (timeLeft === 0) {
            finishExam();
        }
        return () => clearInterval(interval);
    }, [isActive, timeLeft]);

    const toggleTopic = (topic: string) => {
        setSelectedTopics(prev => 
            prev.includes(topic) ? prev.filter(t => t !== topic) : [...prev, topic]
        );
    };

    const formatTime = (seconds: number) => {
        const h = Math.floor(seconds / 3600);
        const m = Math.floor((seconds % 3600) / 60);
        const s = seconds % 60;
        return `${h.toString().padStart(2, '0')}:${m.toString().padStart(2, '0')}:${s.toString().padStart(2, '0')}`;
    };

    const formatDuration = (seconds: number) => {
        const h = Math.floor(seconds / 3600);
        const m = Math.floor((seconds % 3600) / 60);
        const s = seconds % 60;
        if (h > 0) return `${h}h ${m}m ${s}s`;
        return `${m}m ${s}s`;
    };

    const finishExam = () => {
        setIsActive(false);
        setIsFinished(true);
    };

    const calculateGrade = (marks: number, total: number, aThreshold: number) => {
        const percentage = (marks / total) * 100;
        const aPercent = (aThreshold / total) * 100;

        if (marks >= aThreshold) return 'A';
        if (percentage >= aPercent - 10) return 'B';
        if (percentage >= aPercent - 20) return 'C';
        if (percentage >= aPercent - 30) return 'D';
        if (percentage >= aPercent - 40) return 'E';
        return 'U';
    };

    const handleSubmitScore = async () => {
        const marks = parseInt(userMarks);
        if (isNaN(marks) || marks < 0 || marks > paper.totalMarks) {
            alert(`Please enter valid marks between 0 and ${paper.totalMarks}`);
            return;
        }

        const percentage = (marks / paper.totalMarks) * 100;
        const grade = calculateGrade(marks, paper.totalMarks, paper.aGradeThreshold);
        const timeTaken = totalDuration - timeLeft;

        const attempt: PaperAttempt = {
            id: Date.now().toString(),
            paperId: paper.id,
            subjectName: subjectName,
            subjectCode: subjectCode,
            year: paper.year,
            session: paper.session,
            variant: paper.variant,
            paperNumber: paper.paperNumber,
            userMarks: marks,
            totalMarks: paper.totalMarks,
            aGradeThreshold: paper.aGradeThreshold,
            timestamp: Date.now(),
            isExam: true,
            timeTaken: timeTaken,
            struggledTopics: selectedTopics
        };

        setGradeResult({ grade, percentage });
        onComplete(attempt);

        // Trigger AI Feedback
        setIsLoadingFeedback(true);
        try {
            const feedback = await generateExamFeedback(
                subjectName,
                subjectCode,
                paper.paperNumber,
                marks,
                paper.totalMarks,
                grade,
                paper.aGradeThreshold
            );
            setAiFeedback(feedback);
        } catch (error) {
            console.error(error);
            setAiFeedback("Unable to load AI feedback.");
        } finally {
            setIsLoadingFeedback(false);
        }
    };

    const handleExitRequest = () => {
        if (gradeResult) {
            onExit();
        } else {
            setShowExitConfirm(true);
        }
    };

    if (gradeResult) {
        const timeTaken = totalDuration - timeLeft;

        return (
            <div className="flex flex-col items-center justify-center h-full animate-in zoom-in duration-300 p-4 overflow-y-auto">
                <div className="bg-white dark:bg-slate-800 p-8 rounded-2xl shadow-xl border border-gray-200 dark:border-slate-700 max-w-2xl w-full text-center relative overflow-hidden my-auto">
                    <div className="absolute top-0 left-0 w-full h-2 bg-gradient-to-r from-emerald-400 to-blue-500"></div>

                    <div className="w-24 h-24 bg-emerald-100 dark:bg-emerald-900/30 rounded-full flex items-center justify-center mx-auto mb-6 shadow-inner">
                        {gradeResult.grade === 'A' ? (
                            <Award size={48} className="text-emerald-600 dark:text-emerald-400" />
                        ) : (
                            <CheckCircle size={48} className="text-emerald-600 dark:text-emerald-400" />
                        )}
                    </div>

                    <h2 className="text-3xl font-bold text-slate-900 dark:text-white mb-2">Exam Completed</h2>
                    <p className="text-slate-500 dark:text-slate-400 mb-8">
                        {subjectCode} - {paper.year} {paper.session} Paper {paper.paperNumber}
                    </p>

                    <div className="grid grid-cols-1 sm:grid-cols-3 gap-4 mb-8">
                        <div className="bg-slate-50 dark:bg-slate-700/50 p-4 rounded-xl border border-slate-100 dark:border-slate-600 flex flex-col items-center justify-center">
                             <span className="flex items-center justify-center gap-1 text-xs text-slate-500 uppercase font-semibold mb-1">
                                <Clock size={12} /> Time Taken
                            </span>
                            <span className="text-lg font-bold text-slate-900 dark:text-white">
                                {formatDuration(timeTaken)}
                            </span>
                        </div>
                        <div className="bg-slate-50 dark:bg-slate-700/50 p-4 rounded-xl border border-slate-100 dark:border-slate-600 flex flex-col items-center justify-center">
                            <span className="flex items-center justify-center gap-1 text-xs text-slate-500 uppercase font-semibold mb-1">
                                <BarChart size={12} /> Score
                            </span>
                            <span className="text-xl font-bold text-slate-900 dark:text-white">
                                {userMarks}<span className="text-sm text-slate-400">/{paper.totalMarks}</span>
                            </span>
                        </div>
                        <div className={`p-4 rounded-xl border ${gradeResult.grade === 'A' ? 'bg-emerald-50 dark:bg-emerald-900/20 border-emerald-100 dark:border-emerald-800' : 'bg-slate-50 dark:bg-slate-700/50 border-slate-100 dark:border-slate-600'} flex flex-col items-center justify-center`}>
                            <span className="flex items-center justify-center gap-1 text-xs text-slate-500 uppercase font-semibold mb-1">
                                <Award size={12} /> Grade
                            </span>
                            <span className={`text-2xl font-extrabold ${gradeResult.grade === 'A' ? 'text-emerald-600 dark:text-emerald-400' : 'text-slate-900 dark:text-white'}`}>
                                {gradeResult.grade}
                            </span>
                        </div>
                    </div>

                    <div className="bg-blue-50 dark:bg-blue-900/20 p-4 rounded-xl mb-6 text-sm text-blue-800 dark:text-blue-300 border border-blue-100 dark:border-blue-800/30">
                        <p>
                            You scored <strong>{Math.round(gradeResult.percentage)}%</strong>. 
                            The 'A' grade threshold was {paper.aGradeThreshold} ({Math.round((paper.aGradeThreshold / paper.totalMarks) * 100)}%).
                        </p>
                    </div>

                    {/* AI Feedback Section */}
                    <div className="mb-8 text-left bg-gradient-to-br from-indigo-50 to-purple-50 dark:from-slate-800 dark:to-slate-800/50 rounded-xl border border-indigo-100 dark:border-slate-700 p-5 shadow-sm">
                        <div className="flex items-center gap-2 mb-3">
                            <Sparkles size={18} className="text-indigo-600 dark:text-indigo-400" />
                            <h3 className="font-bold text-slate-900 dark:text-white text-sm uppercase tracking-wide">
                                AI Examiner Feedback
                            </h3>
                        </div>

                        {isLoadingFeedback ? (
                            <div className="flex flex-col items-center justify-center py-6 space-y-3">
                                <Spinner />
                                <span className="text-xs text-slate-400">Analyzing your performance...</span>
                            </div>
                        ) : (
                            <div className="text-sm text-slate-700 dark:text-slate-300">
                                {aiFeedback ? (
                                    <MarkdownRenderer content={aiFeedback} />
                                ) : (
                                    <p className="text-slate-400 italic">No feedback available.</p>
                                )}
                            </div>
                        )}
                    </div>

                    <button 
                        onClick={onExit}
                        className="w-full bg-slate-900 hover:bg-slate-800 dark:bg-white dark:hover:bg-gray-100 text-white dark:text-slate-900 py-3.5 rounded-xl font-bold transition-all shadow-lg hover:shadow-xl active:scale-95"
                    >
                        Return to Dashboard
                    </button>
                </div>
            </div>
        );
    }

    return (
        <div className="h-full flex flex-col space-y-6 max-w-5xl mx-auto relative">
            {/* Header / Timer */}
            <div className={`bg-white dark:bg-slate-800 border-b-4 ${isActive ? 'border-orange-500' : 'border-slate-300 dark:border-slate-600'} p-6 rounded-xl shadow-sm flex flex-col md:flex-row justify-between items-center gap-4 transition-colors`}>
                <div>
                    <div className="flex items-center gap-3">
                         <h2 className="text-xl font-bold text-slate-900 dark:text-white">
                             {subjectName} <span className="text-slate-400 font-normal">({subjectCode})</span>
                         </h2>
                         <span className="px-2 py-0.5 bg-gray-100 dark:bg-slate-700 rounded text-xs font-mono text-slate-600 dark:text-slate-300">
                             {paper.year} {paper.session} P{paper.paperNumber}
                         </span>
                    </div>
                    <p className="text-sm text-slate-500 mt-1">
                        {isActive ? 'Exam in progress. Good luck!' : 'Exam finished. Time to mark your work.'}
                    </p>
                </div>

                <div className={`flex items-center gap-3 px-6 py-3 rounded-lg font-mono text-3xl font-bold ${isActive ? 'bg-orange-50 dark:bg-orange-900/20 text-orange-600 dark:text-orange-400' : 'bg-gray-100 dark:bg-slate-700 text-slate-500'}`}>
                    <Timer size={32} className={isActive ? 'animate-pulse' : ''} />
                    {formatTime(timeLeft)}
