import { GoogleGenAI, Chat, Type, Part } from "@google/genai";

// Initialize the client
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const MODEL_NAME = "gemini-3-flash-preview";

export const createTutorSession = (subjectName: string): Chat => {
  return ai.chats.create({
    model: MODEL_NAME,
    config: {
        systemInstruction: `You are an expert Cambridge International Examinations (CAIE) tutor for ${subjectName || 'O and A Levels'}. 
        You help students solve past paper questions, explain difficult concepts, and provide marking scheme insights. 
        You are encouraging, precise, and use Markdown for mathematical formulas and structured answers. 
        If asked about specific past papers, assume the role of an examiner explaining the solution.`
    }
  });
};

export const sendMessageStream = async (
    chat: Chat, 
    message: string,
    imageData: string | null,
    onChunk: (text: string) => void
): Promise<string> => {
    try {
        let content: string | Array<string | Part> = message;

        if (imageData) {
            // Remove data:image/xxx;base64, prefix if present for the API call if it expects raw base64, 
            // but usually the SDK helpers might handle it or we construct the part manually.
            // The @google/genai SDK usually expects standard base64 in inlineData.
            const base64Data = imageData.split(',')[1] || imageData;
            const mimeType = imageData.substring(imageData.indexOf(':') + 1, imageData.indexOf(';'));

            content = [
                { text: message },
                { 
                    inlineData: { 
                        mimeType: mimeType || 'image/jpeg', 
                        data: base64Data 
                    } 
                }
            ];
        }

        const responseStream = await chat.sendMessageStream({
            message: content
        });

        let fullText = "";
        for await (const chunk of responseStream) {
            const text = chunk.text;
            if (text) {
                fullText += text;
                onChunk(text);
            }
        }
        return fullText;
    } catch (error) {
        console.error("Error sending chat message:", error);
        throw error;
    }
}

export const generateExamFeedback = async (
    subjectName: string,
    subjectCode: string,
    paperNumber: number,
    userMarks: number,
    totalMarks: number,
    grade: string,
    threshold: number
): Promise<string> => {
    const prompt = `You are a senior Cambridge International examiner.
    A student just completed a past paper exam simulation.

    Context:
    - Subject: ${subjectName} (${subjectCode})
    - Paper: ${paperNumber}
    - Score: ${userMarks}/${totalMarks}
    - Grade Achieved: ${grade}
    - The 'A' grade threshold was: ${threshold}/${totalMarks}

    Task:
    Provide brief, specific, and actionable feedback (max 150 words).
    1. Analyze their performance based on the grade.
    2. Suggest 2-3 specific high-yield topics or skills usually tested in Paper ${paperNumber} for this subject that they should review to improve (or maintain) this grade. 
       (For example, if it is Math P3, mention complex numbers or integration; if Physics P4, mention fields or quantum physics).
    3. Be encouraging but realistic.

    Output Format:
    Use Markdown. Use bolding for key terms.`;

    try {
        const response = await ai.models.generateContent({
            model: MODEL_NAME,
            contents: prompt,
        });
        return response.text || "Unable to generate feedback at this time.";
    } catch (error) {
        console.error("Error generating feedback:", error);
        return "Sorry, I couldn't generate detailed feedback right now. Please try again later.";
    }
};

export const generateAIStudyPlan = async (
    subjectName: string,
    goal: string,
    days: number
): Promise<{ day: number; title: string }[]> => {
    try {
        const response = await ai.models.generateContent({
            model: MODEL_NAME,
            contents: `Create a study plan for ${subjectName} to achieve the goal: "${goal}".
            The plan must span exactly ${days} days.
            Be specific about topics to cover or tasks to do (e.g., "Review Integration Formulas", "Solve Nov 2021 Paper 1").`,
            config: {
                responseMimeType: "application/json",
                responseSchema: {
                    type: Type.ARRAY,
                    items: {
                        type: Type.OBJECT,
                        properties: {
                            day: { type: Type.INTEGER },
                            title: { type: Type.STRING, description: "A concise description of the study task for this day." }
                        },
                        required: ["day", "title"],
                    },
                },
            }
        });

        if (response.text) {
            return JSON.parse(response.text);
        }
        return [];
    } catch (error) {
        console.error("Error generating study plan:", error);
        return [];
    }
}

import React, { useState, useRef, useEffect } from 'react';
import { Send, User, Bot, Trash2, GraduationCap, Sparkles, ArrowRight, Lightbulb, MessageSquare, Plus, Paperclip, X } from 'lucide-react';
import { Message } from '../types';
import { createTutorSession, sendMessageStream } from '../services/geminiService';
import { MarkdownRenderer } from './MarkdownRenderer';
import { Spinner } from './Spinner';
import { Chat } from '@google/genai';
import { SUBJECTS } from '../services/mockData';

export const TutorInterface: React.FC = () => {
  const [selectedSubjectId, setSelectedSubjectId] = useState<string>('all');
  const [messages, setMessages] = useState<Message[]>([]);
  const [inputValue, setInputValue] = useState('');
  const [selectedImage, setSelectedImage] = useState<string | null>(null);
  const [isTyping, setIsTyping] = useState(false);
  const chatSessionRef = useRef<Chat | null>(null);
  const messagesEndRef = useRef<HTMLDivElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const startNewSession = (subjectId: string) => {
    const subject = SUBJECTS.find(s => s.id === subjectId);
    const subjectName = subject ? `${subject.name} (${subject.level})` : 'O and A Levels';

    chatSessionRef.current = createTutorSession(subjectName);

    setMessages([{
      id: Date.now().toString(),
      role: 'model',
      content: `Hello! I'm your CAIE AI Tutor${subjectId !== 'all' ? ` for ${subjectName}` : ''}. I can help you with Past Papers, Marking Schemes, and difficult concepts. You can even show me a question!`,
      timestamp: Date.now(),
    }]);
  };

  useEffect(() => {
    startNewSession('all');
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  const handleSubjectChange = (e: React.ChangeEvent<HTMLSelectElement>) => {
      const newId = e.target.value;
      setSelectedSubjectId(newId);
      startNewSession(newId);
  };

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages, isTyping, selectedImage]);

  const handleImageSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
      const file = e.target.files?.[0];
      if (file) {
          const reader = new FileReader();
          reader.onloadend = () => {
              setSelectedImage(reader.result as string);
          };
          reader.readAsDataURL(file);
      }
  };

  const handleSendMessage = async (text: string = inputValue) => {
    if ((!text.trim() && !selectedImage) || !chatSessionRef.current) return;

    const userMessage: Message = {
      id: Date.now().toString(),
      role: 'user',
      content: text,
      image: selectedImage || undefined,
      timestamp: Date.now(),
    };

    setMessages(prev => [...prev, userMessage]);
    setInputValue('');
    const imageToSend = selectedImage; // Capture current state before clearing
    setSelectedImage(null);
    setIsTyping(true);

    const modelMessageId = (Date.now() + 1).toString();
    setMessages(prev => [
      ...prev,
      { id: modelMessageId, role: 'model', content: '', timestamp: Date.now(), isLoading: true }
    ]);

    try {
      let accumulatedText = "";

      await sendMessageStream(chatSessionRef.current, userMessage.content, imageToSend, (chunk) => {
        accumulatedText += chunk;
        setMessages(prev => prev.map(msg => 
          msg.id === modelMessageId 
            ? { ...msg, content: accumulatedText, isLoading: false } 
            : msg
        ));
      });

    } catch (error) {
      setMessages(prev => [
        ...prev,
        { id: Date.now().toString(), role: 'model', content: "Sorry, I encountered an error connecting to the AI Tutor. Please check your internet or API key.", timestamp: Date.now() }
      ]);
    } finally {
      setIsTyping(false);
    }
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSendMessage();
    }
  };

  const clearChat = () => {
    startNewSession(selectedSubjectId);
    setSelectedImage(null);
  };

