      {/* Decorative Background */}
      <div className="absolute top-0 left-0 w-full h-full overflow-hidden pointer-events-none z-0">
          <div className="absolute top-[-10%] right-[-10%] w-[300px] h-[300px] bg-emerald-500/5 dark:bg-emerald-500/10 rounded-full blur-[80px]" />
          <div className="absolute bottom-[-10%] left-[-10%] w-[300px] h-[300px] bg-blue-500/5 dark:bg-blue-500/10 rounded-full blur-[80px]" />
      </div>

      {/* Header */}
      <div className="relative z-10 p-4 border-b border-gray-200 dark:border-slate-800 bg-white/80 dark:bg-slate-900/80 backdrop-blur-md flex flex-col sm:flex-row sm:justify-between sm:items-center gap-4">
        <div className="flex items-center space-x-3">
            <div className="p-2.5 bg-gradient-to-br from-emerald-500 to-teal-600 rounded-xl shadow-lg shadow-emerald-500/20">
                <Bot size={24} className="text-white" />
            </div>
            <div>
                <h2 className="text-lg font-bold text-slate-900 dark:text-white leading-tight flex items-center gap-2">
                    AI Tutor
                    <span className="px-2 py-0.5 rounded-full bg-emerald-100 dark:bg-emerald-900/30 text-emerald-700 dark:text-emerald-400 text-[10px] font-bold uppercase tracking-wider">
                        Beta
                    </span>
                </h2>
                <p className="text-xs text-slate-500 dark:text-slate-400 font-medium">Powered by Gemini 3 Flash</p>
            </div>
        </div>

        <div className="flex items-center gap-2 w-full sm:w-auto">
             <div className="relative flex-1 sm:flex-none group">
                 <select 
                    value={selectedSubjectId}
                    onChange={handleSubjectChange}
                    className="w-full sm:w-48 appearance-none bg-gray-50 dark:bg-slate-800 border border-gray-200 dark:border-slate-700 text-slate-900 dark:text-white text-sm rounded-xl pl-3 pr-8 py-2.5 focus:ring-2 focus:ring-emerald-500 outline-none transition-all hover:bg-white dark:hover:bg-slate-700 cursor-pointer"
                 >
                    <option value="all">General Tutor</option>
                    {SUBJECTS.map(s => (
                        <option key={s.id} value={s.id}>{s.name} ({s.level})</option>
                    ))}
                 </select>
                 <div className="absolute right-3 top-1/2 -translate-y-1/2 pointer-events-none text-slate-400">
                     <ArrowRight size={14} className="rotate-90" />
                 </div>
             </div>

            <button 
                onClick={clearChat}
                className="p-2.5 text-slate-400 hover:text-red-500 hover:bg-red-50 dark:hover:bg-red-900/20 rounded-xl transition-colors border border-transparent hover:border-red-100 dark:hover:border-red-900/30"
                title="Clear Chat"
            >
                <Trash2 size={18} />
            </button>
        </div>
      </div>

      {/* Messages Area */}
      <div className="relative z-10 flex-1 overflow-y-auto p-4 space-y-6 custom-scrollbar scroll-smooth">
        {messages.map((msg, index) => (
          <div
            key={msg.id}
            className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'} animate-in fade-in slide-in-from-bottom-2 duration-300 gap-3`}
          >
            {/* Bot Avatar */}
            {msg.role === 'model' && (
                <div className="w-8 h-8 rounded-full bg-emerald-100 dark:bg-emerald-900/50 border border-emerald-200 dark:border-emerald-800 flex items-center justify-center flex-shrink-0 mt-2">
                    <Bot size={16} className="text-emerald-600 dark:text-emerald-400" />
                </div>
            )}

            <div
              className={`max-w-[85%] md:max-w-[75%] px-5 py-4 shadow-sm relative group ${
                msg.role === 'user'
                  ? 'bg-gradient-to-br from-emerald-600 to-teal-600 text-white rounded-2xl rounded-tr-none'
                  : 'bg-white dark:bg-slate-800 text-slate-800 dark:text-slate-200 border border-gray-200 dark:border-slate-700 rounded-2xl rounded-tl-none shadow-md dark:shadow-none'
              }`}
            >
              {msg.image && (
                  <div className="mb-3 rounded-lg overflow-hidden max-w-full">
                      <img src={msg.image} alt="User upload" className="max-w-full h-auto max-h-60 object-contain rounded-lg border border-white/20" />
                  </div>
              )}
              {msg.isLoading && !msg.content ? (
                 <div className="py-1">
                    <Spinner />
                 </div>
              ) : (
                <MarkdownRenderer content={msg.content} />
              )}
            </div>

            {/* User Avatar */}
            {msg.role === 'user' && (
                <div className="w-8 h-8 rounded-full bg-slate-100 dark:bg-slate-800 border border-slate-200 dark:border-slate-700 flex items-center justify-center flex-shrink-0 mt-2">
                    <User size={16} className="text-slate-600 dark:text-slate-400" />
                </div>
            )}
          </div>
        ))}

        {/* Suggestion Chips */}
        {messages.length <= 1 && !isTyping && (
            <div className="mt-8 px-4 animate-in fade-in slide-in-from-bottom-4 delay-200">
                <div className="flex items-center gap-2 mb-4 text-slate-400 dark:text-slate-500">
                    <Sparkles size={14} />
                    <span className="text-xs font-bold uppercase tracking-wider">Suggested Questions</span>
                </div>
                <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
                    {getSuggestions(selectedSubjectId).map((suggestion, idx) => (
                        <button
                            key={idx}
                            onClick={() => handleSendMessage(suggestion.text)}
                            className="flex items-start p-3 text-left bg-white dark:bg-slate-800/40 hover:bg-emerald-50 dark:hover:bg-slate-800 border border-gray-200 dark:border-slate-700 hover:border-emerald-200 dark:hover:border-emerald-900/50 rounded-xl transition-all duration-200 group shadow-sm hover:shadow-md"
                        >
                            <div className="p-2 bg-emerald-50 dark:bg-emerald-900/20 text-emerald-600 dark:text-emerald-400 rounded-lg mr-3 group-hover:scale-110 transition-transform">
                                <suggestion.icon size={16} />
                            </div>
                            <div className="flex-1">
                                <div className="flex justify-between items-start">
                                    <span className="text-xs font-bold text-slate-500 dark:text-slate-400 mb-0.5 uppercase tracking-wide">
                                        {suggestion.label}
                                    </span>
                                    <Plus size={12} className="text-slate-300 dark:text-slate-600 group-hover:text-emerald-500 transition-colors" />
                                </div>
                                <p className="text-sm font-medium text-slate-800 dark:text-slate-200 group-hover:text-emerald-700 dark:group-hover:text-emerald-300 transition-colors line-clamp-2">
                                    {suggestion.text}
                                </p>
                            </div>
                        </button>
                    ))}
                </div>
            </div>
        )}

        {isTyping && messages[messages.length - 1]?.role === 'user' && (
             <div className="flex justify-start animate-in fade-in gap-3 px-1">
                 <div className="w-8 h-8 rounded-full bg-emerald-100 dark:bg-emerald-900/50 border border-emerald-200 dark:border-emerald-800 flex items-center justify-center flex-shrink-0 mt-2">
                    <Bot size={16} className="text-emerald-600 dark:text-emerald-400" />
                 </div>
                 <div className="bg-white dark:bg-slate-800 px-4 py-3 rounded-2xl rounded-tl-none border border-gray-200 dark:border-slate-700 shadow-sm flex items-center">
                     <Spinner />
                 </div>
             </div>
        )}
        <div ref={messagesEndRef} />
      </div>

      {/* Input Area */}
      <div className="relative z-20 p-4 bg-white dark:bg-slate-900 border-t border-gray-200 dark:border-slate-800">
        <div className="max-w-4xl mx-auto">
            {/* Image Preview */}
            {selectedImage && (
                <div className="mb-3 relative inline-block animate-in fade-in slide-in-from-bottom-2">
                    <img src={selectedImage} alt="Preview" className="h-20 w-auto rounded-lg border border-gray-200 dark:border-slate-700 shadow-sm" />
                    <button 
                        onClick={() => setSelectedImage(null)}
                        className="absolute -top-2 -right-2 p-1 bg-white dark:bg-slate-800 rounded-full shadow-md border border-gray-200 dark:border-slate-700 text-slate-500 hover:text-red-500 transition-colors"
                    >
                        <X size={12} />
                    </button>
                </div>
            )}

            <div className="relative flex items-end gap-2">
            <div className="relative flex-1 bg-gray-100 dark:bg-slate-800 rounded-2xl border border-gray-200 dark:border-slate-700 focus-within:ring-2 focus-within:ring-emerald-500/50 focus-within:border-emerald-500 transition-all shadow-inner">
                <textarea
                    value={inputValue}
                    onChange={(e) => setInputValue(e.target.value)}
                    onKeyDown={handleKeyDown}
                    placeholder="Ask about a past paper, marking scheme, or concept..."
                    className="w-full bg-transparent text-slate-900 dark:text-white placeholder-slate-500 dark:placeholder-slate-400 rounded-2xl py-3.5 pl-4 pr-24 resize-none h-[54px] max-h-[150px] focus:outline-none custom-scrollbar"
                    style={{ minHeight: '54px' }}
                />

                <div className="absolute right-2 bottom-2 flex items-center gap-1">
                    <input 
                        type="file" 
                        ref={fileInputRef} 
                        onChange={handleImageSelect} 
                        accept="image/*" 
                        className="hidden" 
                    />
                    <button
                        onClick={() => fileInputRef.current?.click()}
                        className={`p-2 rounded-xl transition-all ${selectedImage ? 'text-emerald-600 bg-emerald-100 dark:bg-emerald-900/30' : 'text-slate-400 hover:text-slate-600 dark:hover:text-slate-300 hover:bg-slate-200 dark:hover:bg-slate-700'}`}
                        title="Upload Image"
                    >
                        <Paperclip size={18} />
                    </button>
                    <button
                        onClick={() => handleSendMessage()}
                        disabled={(!inputValue.trim() && !selectedImage) || isTyping}
                        className="p-2 bg-emerald-600 text-white rounded-xl hover:bg-emerald-500 disabled:opacity-50 disabled:cursor-not-allowed transition-all shadow-md active:scale-95 flex items-center justify-center"
                    >
                        <Send size={18} />
                    </button>
                </div>
            </div>
            </div>
        </div>
        <p className="text-center text-[10px] text-slate-400 dark:text-slate-500 mt-2">
            AI can make mistakes. Double check important information with official CAIE resources.
        </p>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { BookOpen, GraduationCap, Menu, X, FileText, Moon, Sun, History, Timer, Brain, CalendarDays } from 'lucide-react';
import { AppMode, PaperAttempt, UserStats, Achievement, StudyPlan } from './types';
import { Dashboard } from './components/Dashboard';
import { TutorInterface } from './components/TutorInterface';
import { HistoryView } from './components/HistoryView';
import { ExamDashboard } from './components/ExamDashboard';
import { FocusTimer } from './components/FocusTimer';
import { StudyPlanner } from './components/StudyPlanner';

const DEFAULT_ACHIEVEMENTS: Achievement[] = [
    { id: 'first_exam', title: 'First Steps', description: 'Complete your first exam', icon: '🎯', unlocked: false },
    { id: 'streak_3', title: 'Consistent', description: 'Study for 3 days in a row', icon: '🔥', unlocked: false },
    { id: 'score_a', title: 'High Flyer', description: 'Score an A in any paper', icon: '🏆', unlocked: false },
    { id: 'night_owl', title: 'Night Owl', description: 'Complete an exam after 10 PM', icon: '🦉', unlocked: false },
];

const DEFAULT_STATS: UserStats = {
    streak: 0,
    lastStudyDate: '',
    totalMinutesStudied: 0,
    papersCompleted: 0,
    xp: 0
};

const App: React.FC = () => {
  const [activeMode, setActiveMode] = useState<AppMode>(AppMode.PAPERS);
  const [mobileMenuOpen, setMobileMenuOpen] = useState(false);

  // Theme State
  const [theme, setTheme] = useState<'dark' | 'light'>(() => {
    if (typeof window !== 'undefined') {
        const saved = localStorage.getItem('theme');
        if (saved) return saved as 'dark' | 'light';
        return window.matchMedia('(prefers-color-scheme: dark)').matches ? 'dark' : 'light';
    }
    return 'dark';
  });

  // History State
  const [attempts, setAttempts] = useState<PaperAttempt[]>(() => {
    if (typeof window !== 'undefined') {
        const saved = localStorage.getItem('paperAttempts');
        return saved ? JSON.parse(saved) : [];
    }
    return [];
  });

  // Bookmarks State
  const [bookmarkedPapers, setBookmarkedPapers] = useState<string[]>(() => {
      if (typeof window !== 'undefined') {
          const saved = localStorage.getItem('bookmarkedPapers');
          return saved ? JSON.parse(saved) : [];
      }
      return [];
  });

  // Planner State
  const [studyPlans, setStudyPlans] = useState<StudyPlan[]>(() => {
    if (typeof window !== 'undefined') {
        const saved = localStorage.getItem('studyPlans');
        return saved ? JSON.parse(saved) : [];
    }
    return [];
  });

  // Gamification State
  const [userStats, setUserStats] = useState<UserStats>(() => {
      const saved = localStorage.getItem('userStats');
      return saved ? JSON.parse(saved) : DEFAULT_STATS;
  });

  const [achievements, setAchievements] = useState<Achievement[]>(() => {
      const saved = localStorage.getItem('achievements');
      return saved ? JSON.parse(saved) : DEFAULT_ACHIEVEMENTS;
  });

  // Apply Theme
  useEffect(() => {
    const root = window.document.documentElement;
    if (theme === 'dark') {
      root.classList.add('dark');
    } else {
      root.classList.remove('dark');
    }
    localStorage.setItem('theme', theme);
  }, [theme]);

  // Save data to local storage
  useEffect(() => {
    localStorage.setItem('paperAttempts', JSON.stringify(attempts));
  }, [attempts]);

  useEffect(() => {
      localStorage.setItem('bookmarkedPapers', JSON.stringify(bookmarkedPapers));
  }, [bookmarkedPapers]);

  useEffect(() => {
    localStorage.setItem('studyPlans', JSON.stringify(studyPlans));
  }, [studyPlans]);

  useEffect(() => {
      localStorage.setItem('userStats', JSON.stringify(userStats));
      localStorage.setItem('achievements', JSON.stringify(achievements));
  }, [userStats, achievements]);

  // Check Streak on Load
  useEffect(() => {
      const today = new Date().toISOString().split('T')[0];
      if (userStats.lastStudyDate !== today) {
           const lastDate = new Date(userStats.lastStudyDate);
           const diffTime = Math.abs(new Date().getTime() - lastDate.getTime());
           const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24)); 

           if (diffDays > 2) {
               // Lost streak
               setUserStats(prev => ({ ...prev, streak: 0 }));
           }
      }
  }, []);

  const toggleTheme = () => {
    setTheme(prev => prev === 'dark' ? 'light' : 'dark');
  };

  const toggleMobileMenu = () => setMobileMenuOpen(!mobileMenuOpen);

  const toggleBookmark = (paperId: string) => {
      setBookmarkedPapers(prev => 
          prev.includes(paperId) ? prev.filter(id => id !== paperId) : [...prev, paperId]
      );
  };

  const updateGamification = (attempt: PaperAttempt) => {
      const today = new Date().toISOString().split('T')[0];
      const isNewDay = userStats.lastStudyDate !== today;

      let newStreak = userStats.streak;
      if (isNewDay) {
          // Check if consecutive
          if (userStats.lastStudyDate) {
              const lastDate = new Date(userStats.lastStudyDate);
              const yesterday = new Date();
              yesterday.setDate(yesterday.getDate() - 1);
              if (lastDate.toISOString().split('T')[0] === yesterday.toISOString().split('T')[0]) {
                  newStreak += 1;
              } else {
                  newStreak = 1; // Reset or Start new
              }
          } else {
              newStreak = 1;
          }
      }

      const newXP = userStats.xp + 100 + (attempt.userMarks > 0 ? attempt.userMarks : 10);

      const updatedStats = {
          ...userStats,
          streak: newStreak,
          lastStudyDate: today,
          papersCompleted: userStats.papersCompleted + 1,
          totalMinutesStudied: userStats.totalMinutesStudied + (attempt.timeTaken ? Math.floor(attempt.timeTaken / 60) : 30),
          xp: newXP
      };

      setUserStats(updatedStats);

      // Check Achievements
      const newAchievements = achievements.map(ach => {
          if (ach.unlocked) return ach;

          let unlocked = false;
          if (ach.id === 'first_exam') unlocked = true;
          if (ach.id === 'streak_3' && newStreak >= 3) unlocked = true;
          if (ach.id === 'score_a' && attempt.userMarks >= attempt.aGradeThreshold) unlocked = true;
          if (ach.id === 'night_owl') {
              const hour = new Date().getHours();
              if (hour >= 22 || hour < 4) unlocked = true;
          }

          if (unlocked) {
              alert(`🏆 Achievement Unlocked: ${ach.title}!`); // Simple notification
              return { ...ach, unlocked: true, unlockedAt: Date.now() };
          }
          return ach;
      });

      setAchievements(newAchievements);
  };

  const handleSaveAttempt = (attempt: PaperAttempt) => {
    setAttempts(prev => {
        const filtered = prev.filter(p => p.paperId !== attempt.paperId);
        return [attempt, ...filtered];
    });
    updateGamification(attempt);
  };

  // Planner Handlers
  const handleAddPlan = (plan: StudyPlan) => {
      setStudyPlans(prev => [plan, ...prev]);
  };

  const handleUpdatePlan = (updatedPlan: StudyPlan) => {
      setStudyPlans(prev => prev.map(p => p.id === updatedPlan.id ? updatedPlan : p));
  };

  const handleDeletePlan = (id: string) => {
      setStudyPlans(prev => prev.filter(p => p.id !== id));
  };

  const renderContent = () => {
    switch (activeMode) {
      case AppMode.PAPERS:
        return (
            <Dashboard 
                onSaveAttempt={handleSaveAttempt} 
                existingAttempts={attempts} 
                userStats={userStats} 
                achievements={achievements}
                bookmarkedPapers={bookmarkedPapers}
                onToggleBookmark={toggleBookmark}
            />
        );
      case AppMode.EXAM:
        return <ExamDashboard onSaveAttempt={handleSaveAttempt} existingAttempts={attempts} />;
      case AppMode.TUTOR:
        return <TutorInterface />;
      case AppMode.HISTORY:
        return <HistoryView attempts={attempts} />;
      case AppMode.FOCUS:
        return <FocusTimer />;
      case AppMode.PLANNER:
        return (
            <StudyPlanner 
                plans={studyPlans}
                onAddPlan={handleAddPlan}
                onUpdatePlan={handleUpdatePlan}
                onDeletePlan={handleDeletePlan}
            />
        );
      default:
        return <Dashboard onSaveAttempt={handleSaveAttempt} existingAttempts={attempts} userStats={userStats} achievements={achievements} />;
    }
  };

  const navItems = [
    { mode: AppMode.PAPERS, label: 'Past Papers', icon: FileText, color: 'text-blue-500 dark:text-blue-400' },
    { mode: AppMode.EXAM, label: 'Exam Mode', icon: Timer, color: 'text-red-500 dark:text-red-400' },
    { mode: AppMode.PLANNER, label: 'Study Planner', icon: CalendarDays, color: 'text-purple-500 dark:text-purple-400' },
    { mode: AppMode.TUTOR, label: 'AI Tutor', icon: GraduationCap, color: 'text-emerald-500 dark:text-emerald-400' },
    { mode: AppMode.FOCUS, label: 'Focus Timer', icon: Brain, color: 'text-pink-500 dark:text-pink-400' },
    { mode: AppMode.HISTORY, label: 'History', icon: History, color: 'text-orange-500 dark:text-orange-400' },
  ];

  return (
    <div className="min-h-screen bg-gray-50 dark:bg-slate-950 text-slate-900 dark:text-slate-200 font-sans selection:bg-indigo-500/30 selection:text-indigo-900 dark:selection:text-white overflow-hidden flex flex-col md:flex-row transition-colors duration-300">

      {/* Sidebar Navigation (Desktop) */}
      <aside className="hidden md:flex flex-col w-64 bg-white dark:bg-slate-900 border-r border-gray-200 dark:border-slate-800 p-4 transition-colors duration-300">
        <div className="flex items-center space-x-3 px-2 py-4 mb-8">
            <div className="p-2 bg-emerald-600 rounded-lg shadow-lg shadow-emerald-500/20">
                <BookOpen size={24} className="text-white" />
            </div>
            <div>
                <h1 className="text-lg font-bold text-slate-900 dark:text-white leading-tight">
                    CAIE Hub
                </h1>
                <span className="text-xs text-slate-500 dark:text-slate-400">Past Papers & Prep</span>
            </div>
        </div>

        <nav className="flex-1 space-y-2">
            {navItems.map((item) => (
                <button
                    key={item.mode}
                    onClick={() => setActiveMode(item.mode)}
                    className={`w-full flex items-center space-x-3 px-4 py-3 rounded-xl transition-all duration-200 group ${
                        activeMode === item.mode 
                        ? 'bg-slate-100 dark:bg-slate-800 text-slate-900 dark:text-white border border-gray-200 dark:border-slate-700 shadow-sm' 
                        : 'text-slate-500 dark:text-slate-400 hover:bg-slate-50 dark:hover:bg-slate-800/50 hover:text-slate-900 dark:hover:text-white'
                    }`}
                >
                    <item.icon size={20} className={`${activeMode === item.mode ? item.color : 'text-slate-400 dark:text-slate-500 group-hover:text-slate-600 dark:group-hover:text-white'} transition-colors`} />
                    <span className="font-medium">{item.label}</span>
                </button>
            ))}
        </nav>

        <div className="mt-auto pt-6 border-t border-gray-200 dark:border-slate-800/50 space-y-4">
            <button 
                onClick={toggleTheme}
                className="w-full flex items-center justify-center space-x-2 px-4 py-2 rounded-lg bg-gray-100 dark:bg-slate-800 text-slate-600 dark:text-slate-300 hover:bg-gray-200 dark:hover:bg-slate-700 transition-colors"
            >
                {theme === 'dark' ? <Sun size={18} /> : <Moon size={18} />}
                <span className="text-sm font-medium">{theme === 'dark' ? 'Light Mode' : 'Dark Mode'}</span>
            </button>
            <p className="text-xs text-slate-400 text-center">
                Mock Data & AI Powered
            </p>
        </div>
      </aside>

      {/* Mobile Header */}
      <div className="md:hidden flex items-center justify-between p-4 bg-white dark:bg-slate-900 border-b border-gray-200 dark:border-slate-800 sticky top-0 z-50">
         <div className="flex items-center space-x-2">
            <div className="p-1.5 bg-emerald-600 rounded-md">
                <BookOpen size={18} className="text-white" />
            </div>
            <span className="font-bold text-lg text-slate-900 dark:text-white">CAIE Hub</span>
         </div>
         <div className="flex items-center space-x-2">
             <button onClick={toggleTheme} className="p-2 text-slate-600 dark:text-slate-300">
                {theme === 'dark' ? <Sun size={20} /> : <Moon size={20} />}
             </button>
             <button onClick={toggleMobileMenu} className="p-2 text-slate-600 dark:text-slate-300">
                 {mobileMenuOpen ? <X size={24} /> : <Menu size={24} />}
             </button>
         </div>
      </div>

      {/* Mobile Menu Overlay */}
      {mobileMenuOpen && (
          <div className="md:hidden fixed inset-0 z-40 bg-white/95 dark:bg-slate-900/95 backdrop-blur-lg pt-20 px-6">
              <nav className="space-y-4">
                {navItems.map((item) => (
                    <button
                        key={item.mode}
                        onClick={() => {
                            setActiveMode(item.mode);
                            setMobileMenuOpen(false);
                        }}
                        className={`w-full flex items-center space-x-4 p-4 rounded-xl text-lg font-medium transition-all ${
                            activeMode === item.mode 
                            ? 'bg-slate-100 dark:bg-slate-800 text-slate-900 dark:text-white border border-gray-200 dark:border-slate-700' 
                            : 'bg-transparent text-slate-500 dark:text-slate-400'
                        }`}
                    >
                        <item.icon size={24} />
                        <span>{item.label}</span>
                    </button>
                ))}
              </nav>
          </div>
      )}

      {/* Main Content Area */}
      <main className="flex-1 relative overflow-hidden flex flex-col">
        {/* Background Decorative Elements */}
        <div className="absolute top-[-20%] left-[-10%] w-[500px] h-[500px] bg-emerald-400/20 dark:bg-emerald-600/10 rounded-full blur-[128px] pointer-events-none" />
        <div className="absolute bottom-[-20%] right-[-10%] w-[500px] h-[500px] bg-blue-400/20 dark:bg-blue-600/10 rounded-full blur-[128px] pointer-events-none" />

        {/* 
            Conditional Layout:
            - Tutor Mode: Needs fixed height container with overflow hidden (scrolling handled internally)
            - Other Modes: Container scrolls (overflow-y-auto)
        */}
        <div className={`flex-1 p-4 md:p-6 max-w-7xl mx-auto w-full z-10 custom-scrollbar ${activeMode === AppMode.TUTOR || activeMode === AppMode.FOCUS ? 'overflow-hidden flex flex-col' : 'overflow-y-auto'}`}>
            {renderContent()}
        </div>
      </main>
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { PastPaper, PaperAttempt } from '../types';
import { Download, FileText, CheckCircle, Save, XCircle, Timer, Star } from 'lucide-react';

interface PaperCardProps {
  paper: PastPaper;
  subjectCode: string;
  subjectName?: string;
  onSaveAttempt?: (attempt: PaperAttempt) => void;
  previousAttempt?: PaperAttempt;
  isExamMode?: boolean;
  onStartExam?: (paper: PastPaper) => void;
  isBookmarked?: boolean;
  onToggleBookmark?: (paperId: string) => void;
}

const getDifficultyColor = (diff: string) => {
    switch(diff) {
        case 'Very Easy': return 'bg-emerald-100 dark:bg-emerald-500/20 text-emerald-700 dark:text-emerald-400 border-emerald-200 dark:border-emerald-500/50';
        case 'Easy': return 'bg-teal-100 dark:bg-teal-500/20 text-teal-700 dark:text-teal-400 border-teal-200 dark:border-teal-500/50';
        case 'Medium': return 'bg-blue-100 dark:bg-blue-500/20 text-blue-700 dark:text-blue-400 border-blue-200 dark:border-blue-500/50';
        case 'Hard': return 'bg-orange-100 dark:bg-orange-500/20 text-orange-700 dark:text-orange-400 border-orange-200 dark:border-orange-500/50';
        case 'Very Hard': return 'bg-red-100 dark:bg-red-500/20 text-red-700 dark:text-red-400 border-red-200 dark:border-red-500/50';
        default: return 'bg-slate-100 dark:bg-slate-700 text-slate-700 dark:text-slate-300';
    }
};

export const PaperCard: React.FC<PaperCardProps> = ({ 
    paper, 
    subjectCode, 
    subjectName, 
    onSaveAttempt, 
    previousAttempt, 
    isExamMode = false,
    onStartExam,
    isBookmarked,
    onToggleBookmark
}) => {
  const [showScoreInput, setShowScoreInput] = useState(false);
  const [userMarks, setUserMarks] = useState<string>(previousAttempt ? previousAttempt.userMarks.toString() : '');
  const percentage = Math.round((paper.aGradeThreshold / paper.totalMarks) * 100);

  const handleSave = () => {
    if (!userMarks || isNaN(parseInt(userMarks)) || !onSaveAttempt) return;

    const marks = parseInt(userMarks);
    if (marks < 0 || marks > paper.totalMarks) {
        alert(`Marks must be between 0 and ${paper.totalMarks}`);
        return;
    }

    const attempt: PaperAttempt = {
        id: Date.now().toString(),
        paperId: paper.id,
        subjectName: subjectName || 'Unknown',
        subjectCode: subjectCode,
        year: paper.year,
        session: paper.session,
        variant: paper.variant,
        paperNumber: paper.paperNumber,
        userMarks: marks,
        totalMarks: paper.totalMarks,
        aGradeThreshold: paper.aGradeThreshold,
        timestamp: Date.now()
    };

    onSaveAttempt(attempt);
    setShowScoreInput(false);
  };

  return (
    <div className={`bg-white dark:bg-slate-800/50 border ${previousAttempt ? 'border-indigo-300 dark:border-indigo-500/50' : 'border-gray-200 dark:border-slate-700'} rounded-xl p-4 hover:bg-gray-50 dark:hover:bg-slate-800 transition-all group flex flex-col h-full shadow-sm hover:shadow-xl dark:shadow-lg dark:hover:border-slate-600 relative overflow-hidden`}>
      {previousAttempt && (
          <div className="absolute top-0 right-0 bg-indigo-500 text-white text-[10px] px-2 py-0.5 rounded-bl-lg font-bold">
              ATTEMPTED
          </div>
      )}

      {!isExamMode && onToggleBookmark && (
          <button 
            onClick={(e) => {
                e.preventDefault();
                onToggleBookmark(paper.id);
            }}
            className="absolute top-0 right-0 p-2 text-slate-300 hover:text-yellow-400 transition-colors z-10"
            title="Bookmark Paper"
          >
              <Star size={18} className={isBookmarked ? 'fill-yellow-400 text-yellow-400' : ''} />
          </button>
      )}

      <div className="flex justify-between items-start mb-3">
        <div className="pr-6">
            <div className="flex items-center space-x-2">
                <h3 className="text-lg font-bold text-slate-900 dark:text-white">
                    {paper.session === 'May/June' ? 'MJ' : 'ON'} {paper.year}
                </h3>
                <span className="text-xs font-mono text-slate-500 dark:text-slate-400 bg-gray-100 dark:bg-slate-900 px-1.5 py-0.5 rounded border border-gray-200 dark:border-slate-800">
                    {subjectCode}/{paper.variant}
                </span>
            </div>
            <p className="text-sm text-slate-500 dark:text-slate-400 mt-1">Paper {paper.paperNumber}</p>
        </div>
        {!isExamMode && (
            <div className={`px-2 py-1 rounded-lg text-xs font-bold border ${getDifficultyColor(paper.difficulty)}`}>
                {paper.difficulty}
            </div>
        )}
      </div>

      {!isExamMode && (
        <div className="bg-gray-50 dark:bg-slate-900/50 rounded-lg p-3 mb-4 flex justify-between items-center text-sm border border-gray-100 dark:border-slate-800/50">
            <span className="text-slate-600 dark:text-slate-400">A Grade Threshold:</span>
            <div className="text-right">
                <span className="font-bold text-slate-900 dark:text-white block">{paper.aGradeThreshold} / {paper.totalMarks}</span>
                <span className="text-xs text-slate-500">({percentage}%)</span>
            </div>
        </div>
      )}

      {isExamMode && (
         <div className="bg-orange-50 dark:bg-orange-900/20 rounded-lg p-3 mb-4 flex items-center gap-3 text-sm border border-orange-100 dark:border-orange-900/30">
             <Timer size={16} className="text-orange-600 dark:text-orange-400" />
             <span className="text-orange-800 dark:text-orange-300 font-medium">Exam Mode</span>
         </div>
      )}

      {/* Score Input Section (Disabled in Exam Mode selection screen) */}
      {!isExamMode && (
        showScoreInput ? (
            <div className="mb-4 bg-indigo-50 dark:bg-indigo-900/20 p-2 rounded-lg border border-indigo-100 dark:border-indigo-800 flex items-center gap-2 animate-in fade-in slide-in-from-top-1">
                <div className="relative flex-1">
                    <input 
                        type="number" 
                        value={userMarks}
                        onChange={(e) => setUserMarks(e.target.value)}
                        className="w-full bg-white dark:bg-slate-900 border border-gray-300 dark:border-slate-700 rounded px-3 py-1.5 pr-12 text-sm focus:ring-2 focus:ring-indigo-500 outline-none font-medium"
                        autoFocus
                        placeholder="0"
                    />
                    <span className="absolute right-3 top-1/2 -translate-y-1/2 text-gray-400 text-xs font-mono">
                        / {paper.totalMarks}
                    </span>
                </div>
                <button 
                    onClick={handleSave}
                    className="bg-indigo-600 hover:bg-indigo-700 text-white p-2 rounded-lg transition-colors"
                    title="Save Score"
                >
                    <Save size={16} />
                </button>
                <button 
                    onClick={() => setShowScoreInput(false)}
                    className="bg-gray-200 dark:bg-slate-700 text-slate-600 dark:text-slate-300 hover:bg-gray-300 dark:hover:bg-slate-600 p-2 rounded-lg transition-colors"
                    title="Cancel"
                >
                    <XCircle size={16} />
                </button>
            </div>
        ) : (
            <div className="mb-4">
                {previousAttempt ? (
                    <div className="flex items-center justify-between text-sm bg-indigo-50 dark:bg-indigo-900/10 px-3 py-2 rounded-lg border border-indigo-100 dark:border-indigo-800/30">
                        <span className="text-indigo-900 dark:text-indigo-300 font-medium">Your Score:</span>
                        <div className="flex items-center gap-2">
                            <span className="font-bold text-indigo-700 dark:text-indigo-200">{previousAttempt.userMarks} / {paper.totalMarks}</span>
                            <button onClick={() => setShowScoreInput(true)} className="text-xs text-indigo-500 underline hover:text-indigo-700">Edit</button>
                        </div>
                    </div>
                ) : (
                    <button 
                        onClick={() => setShowScoreInput(true)}
                        className="w-full py-2 border border-dashed border-gray-300 dark:border-slate-600 text-gray-500 dark:text-slate-400 rounded-lg text-xs hover:bg-gray-50 dark:hover:bg-slate-800 transition-colors flex items-center justify-center gap-2"
                    >
                        <CheckCircle size={14} />
                        Record Score
                    </button>
                )}
            </div>
        )
      )}

      <div className="mt-auto flex gap-2">
        {isExamMode ? (
            <button 
                onClick={() => onStartExam && onStartExam(paper)}
                className="w-full flex items-center justify-center space-x-2 bg-red-600 hover:bg-red-500 text-white py-2.5 rounded-lg text-sm transition-all shadow-md hover:shadow-lg active:scale-95"
            >
                <Timer size={16} />
                <span className="font-bold">Start Exam</span>
            </button>
        ) : (
            <>
                <a 
                    href={paper.downloadUrl} 
                    target="_blank"
                    rel="noopener noreferrer"
                    download 
                    className="flex-1 flex items-center justify-center space-x-2 bg-indigo-600 hover:bg-indigo-500 text-white py-2.5 rounded-lg text-sm transition-all shadow-md hover:shadow-lg active:scale-95" 
                    title="Download Question Paper"
                >
                    <Download size={16} />
                    <span className="font-medium">Paper</span>
                </a>
                <a 
                    href={paper.markSchemeUrl}
                    target="_blank" 
                    rel="noopener noreferrer"
                    download
                    className="flex-1 flex items-center justify-center space-x-2 bg-gray-200 hover:bg-gray-300 dark:bg-slate-700 dark:hover:bg-slate-600 text-slate-700 dark:text-slate-200 py-2.5 rounded-lg text-sm transition-all border border-gray-300 dark:border-slate-600 hover:border-gray-400 dark:hover:border-slate-500 active:scale-95" 
                    title="Download Mark Scheme"
                >
                    <FileText size={16} />
                    <span className="font-medium">Scheme</span>
                </a>
            </>
        )}
      </div>
    </div>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import { SUBJECTS, generateMockPapers } from '../services/mockData';
import { PastPaper, Subject, DifficultyLevel, PaperAttempt, UserStats, Achievement } from '../types';
import { PaperCard } from './PaperCard';
import { Search, Filter, BookOpen, GraduationCap, Calendar, Layers, Hash, Info, CheckCircle2, Flame, Award, Star, BarChart3, LayoutTemplate } from 'lucide-react';

interface DashboardProps {
    onSaveAttempt?: (attempt: PaperAttempt) => void;
    existingAttempts?: PaperAttempt[];
    userStats?: UserStats;
    achievements?: Achievement[];
    bookmarkedPapers?: string[];
    onToggleBookmark?: (paperId: string) => void;
}

export const Dashboard: React.FC<DashboardProps> = ({ onSaveAttempt, existingAttempts = [], userStats, achievements, bookmarkedPapers = [], onToggleBookmark }) => {
  const [selectedLevel, setSelectedLevel] = useState<'O Level' | 'A Level'>('A Level');
  const [selectedSubjectId, setSelectedSubjectId] = useState<string>(SUBJECTS[0].id);
  const [papers, setPapers] = useState<PastPaper[]>([]);

  // View Mode: 'browse' uses general filters, 'search' uses specific fields
  const [viewMode, setViewMode] = useState<'browse' | 'search'>('browse');

  // Toggle View State
  const [activeTab, setActiveTab] = useState<'stats' | 'filters'>('filters');

  // Browse Filters
  const [difficultyFilter, setDifficultyFilter] = useState<DifficultyLevel | 'All'>('All');
  const [yearRange, setYearRange] = useState<[number, number]>([2010, 2024]);
  const [sessionFilter, setSessionFilter] = useState<'All' | 'May/June' | 'Oct/Nov'>('All');
  const [showSavedOnly, setShowSavedOnly] = useState(false);

  // Quick Search State
  const [searchYear, setSearchYear] = useState<string>('2024');
  const [searchSession, setSearchSession] = useState<'May/June' | 'Oct/Nov'>('May/June');
  const [searchVariant, setSearchVariant] = useState<string>('');

  // Load papers when subject changes
  useEffect(() => {
    const loadedPapers = generateMockPapers(selectedSubjectId);
    setPapers(loadedPapers);
  }, [selectedSubjectId]);

  // Filter Logic
  const filteredPapers = useMemo(() => {
    let result = papers;

    if (viewMode === 'search') {
        result = result.filter(p => {
            const y = parseInt(searchYear);
            const v = parseInt(searchVariant);

            // Year check (if provided, otherwise loose)
            const matchYear = !isNaN(y) ? p.year === y : true;
            const matchSession = p.session === searchSession;
            // Variant check (if provided)
            const matchVariant = !isNaN(v) ? p.variant === v : true;

            return matchYear && matchSession && matchVariant;
        });
    } else {
        // Default Browse Filter Logic
        result = result.filter(p => {
            const matchesDiff = difficultyFilter === 'All' || p.difficulty === difficultyFilter;
            const matchesYear = p.year >= yearRange[0] && p.year <= yearRange[1];
            const matchesSession = sessionFilter === 'All' || p.session === sessionFilter;
            return matchesDiff && matchesYear && matchesSession;
        });
    }

    if (showSavedOnly) {
        result = result.filter(p => bookmarkedPapers.includes(p.id));
    }

    return result.sort((a, b) => {
        // Sort by year desc by default, then session
        if (b.year !== a.year) return b.year - a.year;
        return a.session.localeCompare(b.session);
    });
  }, [papers, viewMode, difficultyFilter, yearRange, sessionFilter, searchYear, searchSession, searchVariant, showSavedOnly, bookmarkedPapers]);

  const currentSubject = SUBJECTS.find(s => s.id === selectedSubjectId);
  const subjectsByLevel = SUBJECTS.filter(s => s.level === selectedLevel);
  const unlockedAchievements = achievements?.filter(a => a.unlocked) || [];

  return (
    <div className="h-full flex flex-col space-y-6">

      {/* View Toggle */}
      <div className="flex justify-between items-center">
          <div className="flex bg-white dark:bg-slate-900 p-1 rounded-xl border border-gray-200 dark:border-slate-800 shadow-sm">
            <button 
                onClick={() => setActiveTab('stats')}
                className={`flex items-center gap-2 px-4 py-2 rounded-lg text-sm font-bold transition-all ${activeTab === 'stats' ? 'bg-indigo-100 dark:bg-indigo-900/30 text-indigo-700 dark:text-indigo-400' : 'text-slate-500 hover:text-slate-900 dark:hover:text-slate-300'}`}
            >
                <BarChart3 size={16} />
                Stats
            </button>
            <button 
                onClick={() => setActiveTab('filters')}
                className={`flex items-center gap-2 px-4 py-2 rounded-lg text-sm font-bold transition-all ${activeTab === 'filters' ? 'bg-emerald-100 dark:bg-emerald-900/30 text-emerald-700 dark:text-emerald-400' : 'text-slate-500 hover:text-slate-900 dark:hover:text-slate-300'}`}
            >
                <LayoutTemplate size={16} />
                Filters
            </button>
          </div>

          {/* Context indicator if filters hidden */}
          {activeTab === 'stats' && (
              <div className="text-xs text-slate-400 font-medium hidden sm:block">
                  Showing results for {currentSubject?.name}
              </div>
          )}
      </div>

      {/* Gamification Summary Banner */}
      {activeTab === 'stats' && userStats && (
        <div className="grid grid-cols-3 gap-4 bg-gradient-to-r from-slate-900 to-slate-800 text-white rounded-2xl p-6 shadow-lg animate-in fade-in slide-in-from-top-4">
             <div className="flex flex-col items-center justify-center p-2 border-r border-slate-700/50">
                <div className="flex items-center gap-2 mb-2 text-orange-400">
                    <Flame size={24} fill="currentColor" />
                    <span className="text-xs font-bold uppercase tracking-wider">Streak</span>
                </div>
                <span className="text-3xl font-bold">{userStats.streak} Days</span>
             </div>
             <div className="flex flex-col items-center justify-center p-2 border-r border-slate-700/50">
                <div className="flex items-center gap-2 mb-2 text-yellow-400">
                    <Star size={24} fill="currentColor" />
                    <span className="text-xs font-bold uppercase tracking-wider">Total XP</span>
                </div>
                <span className="text-3xl font-bold">{userStats.xp}</span>
             </div>
             <div className="flex flex-col items-center justify-center p-2">
                <div className="flex items-center gap-2 mb-2 text-emerald-400">
                    <Award size={24} fill="currentColor" />
                    <span className="text-xs font-bold uppercase tracking-wider">Badges</span>
                </div>
                <span className="text-3xl font-bold">{unlockedAchievements.length}</span>
             </div>
        </div>
      )}

      {/* Header & Controls */}
      {activeTab === 'filters' && (
      <div className="bg-white/70 dark:bg-slate-900/50 border border-gray-200 dark:border-slate-700 rounded-2xl p-6 backdrop-blur-sm shadow-xl dark:shadow-none transition-all duration-300 animate-in fade-in slide-in-from-top-4">
        <div className="flex flex-col md:flex-row md:items-center justify-between gap-4 mb-6">
             <div>
                <h2 className="text-2xl font-bold text-slate-900 dark:text-white flex items-center">
                    <BookOpen className="mr-3 text-emerald-600 dark:text-emerald-500" />
                    Past Paper Archive
                </h2>
                <p className="text-slate-500 dark:text-slate-400 text-sm mt-1">
                    {viewMode === 'browse' ? 'Browse papers by filters' : 'Find a specific paper'}
                </p>
             </div>

             {/* Level Switcher */}
             <div className="flex items-center gap-4">
                 <div className="flex bg-gray-100 dark:bg-slate-800 rounded-lg p-1 border border-gray-200 dark:border-slate-700">
                    <button 
                        onClick={() => setSelectedLevel('O Level')}
                        className={`px-4 py-2 rounded-md text-sm font-medium transition-all ${selectedLevel === 'O Level' ? 'bg-white dark:bg-indigo-600 text-indigo-700 dark:text-white shadow-sm' : 'text-slate-500 dark:text-slate-400 hover:text-slate-900 dark:hover:text-white'}`}
                    >
                        O Level
                    </button>
                    <button 
                        onClick={() => setSelectedLevel('A Level')}
                        className={`px-4 py-2 rounded-md text-sm font-medium transition-all ${selectedLevel === 'A Level' ? 'bg-white dark:bg-indigo-600 text-indigo-700 dark:text-white shadow-sm' : 'text-slate-500 dark:text-slate-400 hover:text-slate-900 dark:hover:text-white'}`}
                    >
                        A Level
                    </button>
                 </div>
             </div>
        </div>

        {/* View Mode Tabs */}
        <div className="flex space-x-1 border-b border-gray-200 dark:border-slate-700 mb-6">
             <button
                onClick={() => setViewMode('browse')}
                className={`pb-2 px-4 text-sm font-medium transition-all relative ${viewMode === 'browse' ? 'text-emerald-600 dark:text-emerald-400' : 'text-slate-500 dark:text-slate-400 hover:text-slate-800 dark:hover:text-slate-200'}`}
             >
                <div className="flex items-center gap-2">
                    <Filter size={16} />
                    Browse Filters
                </div>
                {viewMode === 'browse' && <div className="absolute bottom-0 left-0 right-0 h-0.5 bg-emerald-600 dark:bg-emerald-400 rounded-t-full" />}
             </button>
             <button
                onClick={() => setViewMode('search')}
                className={`pb-2 px-4 text-sm font-medium transition-all relative ${viewMode === 'search' ? 'text-blue-600 dark:text-blue-400' : 'text-slate-500 dark:text-slate-400 hover:text-slate-800 dark:hover:text-slate-200'}`}
             >
                <div className="flex items-center gap-2">
                    <Search size={16} />
                    Quick Search
                </div>
                {viewMode === 'search' && <div className="absolute bottom-0 left-0 right-0 h-0.5 bg-blue-600 dark:bg-blue-400 rounded-t-full" />}
             </button>
        </div>

        <div className="grid grid-cols-1 gap-6">
            {/* Subject Select (Always Visible) */}
            <div className="w-full">
                <label className="text-xs text-slate-500 dark:text-slate-400 mb-1 block">Subject</label>
                <select 
                    value={selectedSubjectId}
                    onChange={(e) => setSelectedSubjectId(e.target.value)}
                    className="w-full bg-white dark:bg-slate-800 text-slate-900 dark:text-white border border-gray-300 dark:border-slate-700 rounded-xl px-4 py-3 focus:ring-2 focus:ring-emerald-500 outline-none appearance-none shadow-sm transition-all"
                >
                    {subjectsByLevel.map(s => (
                        <option key={s.id} value={s.id}>{s.name} ({s.code})</option>
                    ))}
                </select>
            </div>

            {viewMode === 'browse' ? (
                <div className="space-y-4 animate-in fade-in slide-in-from-top-2 duration-300">
                    <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                        {/* Difficulty Filter */}
                        <div>
                            <label className="text-xs text-slate-500 dark:text-slate-400 mb-1 block">Difficulty (by Threshold)</label>
                            <select 
                                value={difficultyFilter}
                                onChange={(e) => setDifficultyFilter(e.target.value as any)}
                                className="w-full bg-white dark:bg-slate-800 text-slate-900 dark:text-white border border-gray-300 dark:border-slate-700 rounded-xl px-4 py-3 focus:ring-2 focus:ring-emerald-500 outline-none shadow-sm"
                            >
                                <option value="All">All Difficulties</option>
                                <option value="Very Easy">Very Easy (Threshold &gt;=75%)</option>
                                <option value="Easy">Easy (68-74%)</option>
                                <option value="Medium">Medium (62-67%)</option>
                                <option value="Hard">Hard (56-61%)</option>
                                <option value="Very Hard">Very Hard (&lt;=55%)</option>
                            </select>
                        </div>

                        {/* Session Filter */}
                        <div>
                            <label className="text-xs text-slate-500 dark:text-slate-400 mb-1 block">Session</label>
                            <select 
                                value={sessionFilter}
                                onChange={(e) => setSessionFilter(e.target.value as any)}
                                className="w-full bg-white dark:bg-slate-800 text-slate-900 dark:text-white border border-gray-300 dark:border-slate-700 rounded-xl px-4 py-3 focus:ring-2 focus:ring-emerald-500 outline-none shadow-sm"
                            >
                                <option value="All">All Sessions</option>
                                <option value="May/June">May/June</option>
                                <option value="Oct/Nov">Oct/Nov</option>
                            </select>
                        </div>

                        {/* Year Range */}
                        <div>
                            <label className="text-xs text-slate-500 dark:text-slate-400 mb-1 block">Years: {yearRange[0]} - {yearRange[1]}</label>
                            <input 
                                type="range"
                                min="2010"
                                max="2024"
                                value={yearRange[0]}
                                onChange={(e) => setYearRange([parseInt(e.target.value), yearRange[1]])}
                                className="w-full h-2 bg-gray-200 dark:bg-slate-700 rounded-lg appearance-none cursor-pointer accent-emerald-500"
                            />
                        </div>
                    </div>

                    <div className="flex items-center">
                        <button
                            onClick={() => setShowSavedOnly(!showSavedOnly)}
                            className={`flex items-center gap-2 px-3 py-1.5 rounded-lg text-sm font-medium transition-colors border ${showSavedOnly ? 'bg-yellow-50 dark:bg-yellow-900/20 text-yellow-700 dark:text-yellow-400 border-yellow-200 dark:border-yellow-700' : 'bg-transparent text-slate-500 border-transparent hover:bg-slate-100 dark:hover:bg-slate-800'}`}
                        >
                            <Star size={16} className={showSavedOnly ? 'fill-current' : ''} />
                            {showSavedOnly ? 'Showing Saved' : 'Show Saved Only'}
                        </button>
                    </div>
                </div>
            ) : (
                <div className="grid grid-cols-1 md:grid-cols-3 gap-4 p-4 bg-blue-50/50 dark:bg-blue-900/20 rounded-xl border border-blue-100 dark:border-blue-800/50 animate-in fade-in slide-in-from-top-2 duration-300">
                     <div>
                        <label className="text-xs text-blue-600 dark:text-blue-400 mb-1 flex items-center gap-1">
                            <Calendar size={12} />
                            Year
                        </label>
                        <input 
                            type="number"
                            placeholder="e.g. 2024"
                            value={searchYear}
                            onChange={(e) => setSearchYear(e.target.value)}
                            className="w-full bg-white dark:bg-slate-800 text-slate-900 dark:text-white border border-blue-200 dark:border-blue-800 rounded-xl px-4 py-3 focus:ring-2 focus:ring-blue-500 outline-none shadow-sm placeholder-slate-400"
                        />
                     </div>
                     <div>
                        <label className="text-xs text-blue-600 dark:text-blue-400 mb-1 flex items-center gap-1">
                            <Layers size={12} />
                            Session
                        </label>
                        <select 
                            value={searchSession}
                            onChange={(e) => setSearchSession(e.target.value as any)}
                            className="w-full bg-white dark:bg-slate-800 text-slate-900 dark:text-white border border-blue-200 dark:border-blue-800 rounded-xl px-4 py-3 focus:ring-2 focus:ring-blue-500 outline-none shadow-sm"
                        >
                            <option value="May/June">May/June</option>
                            <option value="Oct/Nov">Oct/Nov</option>
                        </select>
                     </div>
                     <div>
                        <label className="text-xs text-blue-600 dark:text-blue-400 mb-1 flex items-center gap-1">
                            <Hash size={12} />
                            Variant (e.g. 12, 22)
                        </label>
                        <input 
                            type="text"
                            placeholder="Optional"
                            value={searchVariant}
                            onChange={(e) => setSearchVariant(e.target.value)}
                            className="w-full bg-white dark:bg-slate-800 text-slate-900 dark:text-white border border-blue-200 dark:border-blue-800 rounded-xl px-4 py-3 focus:ring-2 focus:ring-blue-500 outline-none shadow-sm placeholder-slate-400"
                        />
                     </div>
                </div>
            )}
        </div>
      </div>
      )}

      {/* Grid */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-4 overflow-y-auto pb-4 custom-scrollbar">
        {filteredPapers.map((paper) => (
            <PaperCard 
                key={paper.id} 
                paper={paper} 
                subjectCode={currentSubject?.code || ''}
                subjectName={currentSubject?.name}
                onSaveAttempt={onSaveAttempt}
                previousAttempt={existingAttempts.find(a => a.paperId === paper.id)}
                isBookmarked={bookmarkedPapers.includes(paper.id)}
                onToggleBookmark={onToggleBookmark}
            />
        ))}
        {filteredPapers.length === 0 && (
            <div className="col-span-full flex flex-col items-center justify-center py-20 text-slate-500 dark:text-slate-500">
                <div className="bg-gray-100 dark:bg-slate-800/50 p-6 rounded-full mb-4">
                    <Search size={48} className="opacity-50" />
                </div>
                <h3 className="text-lg font-medium mb-2">No papers found</h3>
                <p className="text-sm opacity-70 text-center max-w-md">
                    {viewMode === 'search' 
                        ? `We couldn't find a paper for ${currentSubject?.name} in ${searchSession} ${searchYear} with variant ${searchVariant || 'any'}.`
                        : "Try adjusting your filters to see more results."}
                </p>
            </div>
        )}
      </div>
    </div>
  );
};
